import { Transaction } from '../types';
import { useLocation } from 'react-router-dom';

export const Journal: React.FC = () => {
  const { state, dispatch } = useFinance();
  const [searchTerm, setSearchTerm] = useState('');
  const [editingTx, setEditingTx] = useState<Transaction | null>(null);
  const location = useLocation();
  const searchInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
      // Focus search input if navigated here via Ctrl+F (Global Search shortcut)
      if (location.state && (location.state as any).focusSearch) {
          if (searchInputRef.current) {
              searchInputRef.current.focus();
          }
          // Clear history state to prevent refocusing on refresh (optional but cleaner)
          window.history.replaceState({}, document.title);
      }
  }, [location]);

  const filteredTransactions = useMemo(() => {
    return state.transactions.filter(t => {
      const acc = state.accounts.find(c => c.id === t.accountId);
      const searchStr = (t.note + (acc?.name || '') + t.amount).toLowerCase();
      return searchStr.includes(searchTerm.toLowerCase());
    });
  }, [state.transactions, state.accounts, searchTerm]);

  const handleDelete = (id: string) => {
      if (window.confirm('Are you sure you want to delete this transaction? This action cannot be undone.')) {
          dispatch({ type: 'DELETE_TRANSACTION', payload: id });
      }
  };

  return (
    <div className="space-y-6 pb-20 md:pb-0 animate-fade-in">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold text-white tracking-tight">Journal</h1>
          <p className="text-gray-400 text-sm mt-1">Audit Log & History</p>
        </div>
      </div>

      <div className="glass-panel p-2 rounded-xl flex gap-4 border border-white/10 sticky top-16 md:relative md:top-0 z-20">
        <div className="flex-1 flex items-center gap-2 bg-gray-900/50 px-3 py-2.5 rounded-lg border border-gray-700/50 focus-within:border-gold-500/50 transition-colors">
           <Search size={18} className="text-gray-500" />
           <input 
             ref={searchInputRef}
             type="text" 
             placeholder="Search transactions..." 
             className="bg-transparent text-white outline-none w-full text-sm placeholder-gray-600"
             value={searchTerm}
             onChange={e => setSearchTerm(e.target.value)}
           />
        </div>
      </div>

      {/* Desktop Table View */}
      <div className="hidden md:block glass-card rounded-2xl overflow-hidden border border-white/5">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm text-gray-400">
            <thead className="bg-gray-900/80 text-gray-500 uppercase font-bold text-xs tracking-wider">
              <tr>
                <th className="p-4">Date</th>
                <th className="p-4">Account</th>
                <th className="p-4">Note</th>
                <th className="p-4 text-right">Amount</th>
                <th className="p-4 w-20 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/5">
              {filteredTransactions.map(t => {
                const acc = state.accounts.find(c => c.id === t.accountId);
                return (
                  <tr key={t.id} className="hover:bg-white/5 transition-colors group">
                    <td className="p-4 whitespace-nowrap">{format(parseISO(t.date), 'MMM d, yyyy')}</td>
                    <td className="p-4">
                      <div className="flex items-center gap-2">
                         {/* Removed color since Account doesn't have it, can add later */}
                        <span className="text-gray-200 font-medium">{acc?.name}</span>
                      </div>
                    </td>
                    <td className="p-4 max-w-xs truncate text-gray-500">{t.note || '-'}</td>
                    <td className={`p-4 text-right font-bold ${t.type === 'income' ? 'text-emerald-400' : 'text-gray-300'}`}>
                      {t.type === 'income' ? '+' : '-'} {t.amount.toLocaleString()}
                    </td>
                    <td className="p-4">
                        <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button 
                                onClick={() => setEditingTx(t)}
                                className="text-gray-500 hover:text-blue-400 p-1.5 rounded hover:bg-blue-900/20 transition-colors"
                                title="Edit"
                            >
                                <Pencil size={16} />
                            </button>
                            <button 
                                onClick={() => handleDelete(t.id)}
                                className="text-gray-500 hover:text-red-400 p-1.5 rounded hover:bg-red-900/20 transition-colors"
                                title="Delete"
                            >
                                <Trash2 size={16} />
                            </button>
                        </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Mobile Card View */}
      <div className="md:hidden space-y-3">
        {filteredTransactions.map(t => {
          const acc = state.accounts.find(c => c.id === t.accountId);
          return (
            <div key={t.id} className="glass-card p-4 rounded-xl border border-white/5 flex flex-col gap-3">
              <div className="flex justify-between items-start">
                <div className="flex flex-col">
                  <span className="text-xs text-gray-500 font-medium uppercase tracking-wider mb-1 flex items-center gap-1.5">
                    <Calendar size={12} /> {format(parseISO(t.date), 'MMM d, yyyy')}
                  </span>
                  <div className="flex items-center gap-2">
                    <span className="text-gray-200 font-semibold">{acc?.name}</span>
                  </div>
                </div>
                <div className={`text-right font-bold text-lg ${t.type === 'income' ? 'text-emerald-400' : 'text-gray-200'}`}>
                  {t.type === 'income' ? '+' : '-'} {t.amount.toLocaleString()}
                </div>
              </div>

              {t.note && (
                <p className="text-sm text-gray-400 italic">"{t.note}"</p>
              )}

              <div className="flex items-center justify-end gap-3 pt-3 border-t border-white/5">
                <button 
                  onClick={() => setEditingTx(t)}
                  className="flex items-center gap-2 px-3 py-1.5 bg-blue-500/10 text-blue-400 rounded-lg text-xs font-bold"
                >
                  <Pencil size={14} /> Edit
                </button>
                <button 
                  onClick={() => handleDelete(t.id)}
                  className="flex items-center gap-2 px-3 py-1.5 bg-red-500/10 text-red-400 rounded-lg text-xs font-bold"
                >
                  <Trash2 size={14} /> Delete
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {filteredTransactions.length === 0 && (
         <div className="p-12 text-center text-gray-500 glass-card rounded-2xl border border-dashed border-white/10">
           No transactions found matching your search.
         </div>
      )}

      <Modal 
        isOpen={!!editingTx} 
        onClose={() => setEditingTx(null)}
        title="Edit Transaction"
      >
          {editingTx && (
              <TransactionForm 
                initialData={editingTx} 
                onComplete={() => setEditingTx(null)} 
              />
          )}
      </Modal>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { useFinance } from '../context/FinanceContext';
import { format, startOfMonth, endOfMonth, parseISO, isWithinInterval, startOfYear, endOfYear } from 'date-fns';
import { PieChart, Pie, Cell, ResponsiveContainer } from 'recharts';
import { ChevronLeft, ChevronRight, Settings, Target, CheckSquare, Square, Copy, Calendar, Lock } from 'lucide-react';
import { Modal } from '../components/ui/Modal';
import { MonthlyBudget } from '../types';

export const Budget: React.FC = () => {
  const { state, dispatch } = useFinance();
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [viewMode, setViewMode] = useState<'monthly' | 'yearly'>('monthly');
  const [isManageOpen, setIsManageOpen] = useState(false);

  // Copy Modal State
  const [isCopyModalOpen, setIsCopyModalOpen] = useState(false);
  const [copyTargetType, setCopyTargetType] = useState<'single' | 'year'>('single');
  const [copyTargetValue, setCopyTargetValue] = useState(''); // YYYY-MM for single, YYYY for year

  const currency = state.businessProfile.baseCurrency || 'QAR';

  const budgetKey = viewMode === 'monthly' ? format(selectedDate, 'yyyy-MM') : format(selectedDate, 'yyyy');
  const periodStart = viewMode === 'monthly' ? startOfMonth(selectedDate) : startOfYear(selectedDate);
  const periodEnd = viewMode === 'monthly' ? endOfMonth(selectedDate) : endOfYear(selectedDate);

  // --- YEARLY AGGREGATION LOGIC ---
  const calculatedYearlyBudget = useMemo(() => {
      if (viewMode !== 'yearly') return undefined;
      const year = format(selectedDate, 'yyyy');

      let totalLimit = 0;
      const aggregatedCategoryLimits: Record<string, number> = {};
      const allVisibleAccountIds = new Set<string>();

      // Iterate through all 12 months of the selected year
      for (let i = 1; i <= 12; i++) {
          const monthKey = `${year}-${String(i).padStart(2, '0')}`;
          const monthBudget = state.monthlyBudgets?.find(b => b.monthKey === monthKey);

          if (monthBudget) {
              totalLimit += monthBudget.limit;

              // Sum category limits
              if (monthBudget.categoryLimits) {
                  Object.entries(monthBudget.categoryLimits).forEach(([accId, limit]) => {
                      aggregatedCategoryLimits[accId] = (aggregatedCategoryLimits[accId] || 0) + limit;
                  });
              }

              // Collect visible accounts (Union of all months)
              if (monthBudget.visibleAccountIds) {
                  monthBudget.visibleAccountIds.forEach(id => allVisibleAccountIds.add(id));
              }
          }
      }

      const derived: MonthlyBudget = {
          monthKey: year,
          limit: totalLimit,
          categoryLimits: aggregatedCategoryLimits,
          visibleAccountIds: Array.from(allVisibleAccountIds)
      };
      return derived;

  }, [viewMode, selectedDate, state.monthlyBudgets]);

  // Get existing budget for this period (or derived if yearly)
  const existingBudget = viewMode === 'yearly' 
      ? calculatedYearlyBudget 
      : state.monthlyBudgets?.find(b => b.monthKey === budgetKey);

  const categoryLimits: Record<string, number> = existingBudget?.categoryLimits || {};

  // Fallback to all Expense accounts if no budget exists/visibility defined
  const visibleAccountIds = existingBudget?.visibleAccountIds && existingBudget.visibleAccountIds.length > 0
      ? existingBudget.visibleAccountIds
      : state.accounts.filter(c => c.class === 'Expenses').map(c => c.id);

  // Calculate actual spending per account for this period
  const actualSpending = useMemo(() => {
    const spending: Record<string, number> = {};
    state.transactions.filter(t => {
      const d = parseISO(t.date);
      return isWithinInterval(d, { start: periodStart, end: periodEnd }) && t.type === 'expense';
    }).forEach(t => {
      spending[t.accountId] = (spending[t.accountId] || 0) + t.amount;
    });
    return spending;
  }, [state.transactions, periodStart, periodEnd]);

  // Expense Accounts
  const allExpenseAccounts = state.accounts.filter(c => c.class === 'Expenses');
  const activeAccounts = allExpenseAccounts.filter(c => visibleAccountIds.includes(c.id));

  // Handlers
  const handleLimitChange = (accId: string, val: string) => {
      if (viewMode === 'yearly') return; // Prevent editing in yearly mode

      const limit = parseFloat(val) || 0;
      const newLimits = { ...categoryLimits, [accId]: limit };

      // Calculate Total from visible
      const totalLimit = Object.entries(newLimits)
        .filter(([id]) => visibleAccountIds.includes(id))
        .reduce((sum, [_, amt]) => sum + (amt as number), 0);

      dispatch({
          type: 'SET_MONTHLY_BUDGET',
          payload: {
              monthKey: budgetKey,
              limit: totalLimit,
              categoryLimits: newLimits,
              visibleAccountIds
          }
      });
  };

  const handleVisibleToggle = (accId: string) => {
      if (viewMode === 'yearly') return; // Prevent editing visibility in yearly mode directly (though aggregation handles it)

      const newVisible = visibleAccountIds.includes(accId) 
        ? visibleAccountIds.filter(id => id !== accId)
        : [...visibleAccountIds, accId];

      const totalLimit = Object.entries(categoryLimits)
        .filter(([id]) => newVisible.includes(id))
        .reduce((sum, [_, amt]) => sum + (amt as number), 0);

      dispatch({
          type: 'SET_MONTHLY_BUDGET',
          payload: {
              monthKey: budgetKey,
              limit: totalLimit,
              categoryLimits,
              visibleAccountIds: newVisible
          }
      });
  };

  const changePeriod = (delta: number) => {
      const newDate = new Date(selectedDate);
      if (viewMode === 'monthly') newDate.setMonth(newDate.getMonth() + delta);
      else newDate.setFullYear(newDate.getFullYear() + delta);
      setSelectedDate(newDate);
  };

  const handleCopyBudget = (e: React.FormEvent) => {
      e.preventDefault();
      // Ensure we are copying from a concrete monthly record
      if (!existingBudget || viewMode === 'yearly') return;

      if (!copyTargetValue) {
          alert("Please select a target.");
          return;
      }

      const targets: string[] = [];

      if (copyTargetType === 'single') {
          // Input type="month" returns YYYY-MM
          targets.push(copyTargetValue);
      } else {
          // Input type="number" returns YYYY
          const year = parseInt(copyTargetValue);
          if (isNaN(year) || year < 2000 || year > 2100) {
              alert("Invalid year.");
              return;
          }
          for (let i = 1; i <= 12; i++) {
              const m = String(i).padStart(2, '0');
              targets.push(`${year}-${m}`);
          }
      }

      // Perform Copy
      targets.forEach(targetKey => {
          dispatch({
              type: 'SET_MONTHLY_BUDGET',
              payload: {
                  monthKey: targetKey,
                  limit: existingBudget.limit,
                  categoryLimits: { ...existingBudget.categoryLimits },
                  visibleAccountIds: [...existingBudget.visibleAccountIds]
              }
          });
      });

      alert(`Budget copied to ${targets.length} month(s).`);
      setIsCopyModalOpen(false);
      setCopyTargetValue('');
  };

  // Stats
  const totalBudget = existingBudget?.limit || 0;
  const totalActual = activeAccounts.reduce((sum, cat) => sum + (actualSpending[cat.id] || 0), 0);
  const remaining = totalBudget - totalActual;
  const percentage = totalBudget > 0 ? (totalActual / totalBudget) * 100 : 0;

  const chartData = [
      { name: 'Used', value: totalActual, color: percentage > 100 ? '#ef4444' : '#3b82f6' },
      { name: 'Remaining', value: Math.max(0, remaining), color: '#1f2937' }
  ];

  return (
    <div className="space-y-6 pb-20 md:pb-0 animate-slide-up">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
            <h1 className="text-3xl font-bold text-white tracking-tight">Budget Planner</h1>
            <p className="text-gray-400 text-sm">
                {viewMode === 'monthly' 
                    ? `Allocate funds for ${format(selectedDate, 'MMMM yyyy')}` 
                    : `Yearly Aggregation for ${format(selectedDate, 'yyyy')}`
                }
            </p>
        </div>
        <div className="flex items-center gap-4">
            <div className="bg-gray-900 rounded-lg p-1 border border-gray-700 flex">
                <button onClick={() => setViewMode('monthly')} className={`px-3 py-1.5 rounded-md text-xs font-bold transition-all ${viewMode === 'monthly' ? 'bg-primary text-white' : 'text-gray-400 hover:text-white'}`}>Monthly</button>
                <button onClick={() => setViewMode('yearly')} className={`px-3 py-1.5 rounded-md text-xs font-bold transition-all ${viewMode === 'yearly' ? 'bg-primary text-white' : 'text-gray-400 hover:text-white'}`}>Yearly</button>
            </div>
            <div className="flex items-center gap-2 bg-gray-900 rounded-lg p-1 border border-gray-700">
                <button onClick={() => changePeriod(-1)} className="p-2 hover:bg-gray-800 rounded-lg text-gray-400"><ChevronLeft size={20}/></button>
                <span className="font-mono text-sm font-bold w-32 text-center text-white">{viewMode === 'monthly' ? format(selectedDate, 'MMM yyyy') : format(selectedDate, 'yyyy')}</span>
                <button onClick={() => changePeriod(1)} className="p-2 hover:bg-gray-800 rounded-lg text-gray-400"><ChevronRight size={20}/></button>
            </div>
            {viewMode === 'monthly' && (
                <button 
                    onClick={() => setIsCopyModalOpen(true)} 
                    disabled={!existingBudget}
                    className="p-2.5 bg-gray-800 hover:bg-gray-700 text-white rounded-lg border border-gray-700 transition-colors disabled:opacity-30 disabled:cursor-not-allowed"
                    title="Copy Budget to other months"
                >
                    <Copy size={18} />
                </button>
            )}
            <button 
                onClick={() => setIsManageOpen(true)} 
                className="p-2.5 bg-gray-800 hover:bg-gray-700 text-white rounded-lg border border-gray-700 transition-colors disabled:opacity-30 disabled:cursor-not-allowed"
                disabled={viewMode === 'yearly'}
                title={viewMode === 'yearly' ? "Switch to Monthly to manage categories" : "Manage Categories"}
            >
                <Settings size={18} />
            </button>
        </div>
      </div>

      {viewMode === 'yearly' && (
          <div className="bg-blue-900/20 border border-blue-500/30 p-3 rounded-xl flex items-center gap-3 text-sm text-blue-300">
              <Lock size={16} />
              <span>Yearly view is read-only. It represents the sum of all monthly budgets. Edit specific months to adjust the yearly plan.</span>
          </div>
      )}

      {/* Overview Card */}
      <div className="glass-card p-6 rounded-2xl flex flex-col md:flex-row items-center gap-8 border border-white/5 bg-gray-900/50">
           <div className="relative w-32 h-32 flex-shrink-0">
               <ResponsiveContainer width="100%" height="100%">
                   <PieChart>
                       <Pie data={chartData} innerRadius={35} outerRadius={50} dataKey="value" stroke="none">
                            {chartData.map((entry, index) => <Cell key={index} fill={entry.color} />)}
                       </Pie>
                   </PieChart>
               </ResponsiveContainer>
               <div className="absolute inset-0 flex items-center justify-center flex-col">
                   <span className="text-xs text-gray-500">Spent</span>
                   <span className={`font-bold ${percentage > 100 ? 'text-red-500' : 'text-blue-500'}`}>{percentage.toFixed(0)}%</span>
               </div>
           </div>

           <div className="flex-1 grid grid-cols-2 md:grid-cols-3 gap-6 text-center md:text-left">
               <div>
                   <p className="text-xs uppercase text-gray-500 font-bold">Total Budget</p>
                   <p className="text-2xl font-bold text-white mt-1">{currency} {totalBudget.toLocaleString()}</p>
               </div>
               <div>
                   <p className="text-xs uppercase text-gray-500 font-bold">Actual Spent</p>
                   <p className={`text-2xl font-bold mt-1 ${totalActual > totalBudget ? 'text-red-400' : 'text-white'}`}>{currency} {totalActual.toLocaleString()}</p>
               </div>
               <div>
                   <p className="text-xs uppercase text-gray-500 font-bold">Remaining</p>
                   <p className={`text-2xl font-bold mt-1 ${remaining < 0 ? 'text-red-500' : 'text-emerald-400'}`}>{currency} {remaining.toLocaleString()}</p>
               </div>
           </div>
      </div>

      {/* Category List */}
      <div className="space-y-4">
          <div className="flex justify-between items-end border-b border-gray-800 pb-2">
            <h3 className="text-lg font-bold text-white">Category Allocations</h3>
            {viewMode === 'yearly' && <span className="text-xs text-gray-500 italic"><Lock size={12} className="inline mr-1"/> Aggregated Values</span>}
          </div>
          <div className="grid gap-3 md:grid-cols-2 lg:grid-cols-3">
              {activeAccounts.map(cat => {
                  const limit = categoryLimits[cat.id] || 0;
                  const spent = actualSpending[cat.id] || 0;
                  const catRemaining = limit - spent;
                  const catPercent = limit > 0 ? (spent / limit) * 100 : 0;

                  return (
                      <div key={cat.id} className={`bg-gray-950/50 border ${viewMode === 'yearly' ? 'border-gray-800/50' : 'border-gray-800'} p-4 rounded-xl flex flex-col gap-3 group hover:border-gray-700 transition-colors`}>
                          <div className="flex justify-between items-start">
                              <div className="flex items-center gap-2">
                                  {/* No color in new Account, use generic dot */}
                                  <div className="w-2 h-2 rounded-full bg-blue-500"/>
                                  <span className="font-medium text-gray-300">{cat.name}</span>
                              </div>
                              <div className={`flex items-center gap-1 bg-gray-900 rounded-lg border border-gray-800 px-2 py-1 transition-all ${viewMode === 'monthly' ? 'focus-within:border-blue-500 focus-within:ring-1 focus-within:ring-blue-500' : 'opacity-70 cursor-not-allowed'}`}>
                                  {viewMode === 'yearly' && <Lock size={10} className="text-gray-600" />}
                                  <span className="text-xs text-gray-500">{currency}</span>
                                  <input 
                                    type="number" 
                                    className={`w-20 bg-transparent text-right text-sm font-bold text-white outline-none ${viewMode === 'yearly' ? 'cursor-not-allowed text-gray-400' : ''}`}
                                    placeholder="0"
                                    value={limit || ''}
                                    onChange={e => handleLimitChange(cat.id, e.target.value)}
                                    disabled={viewMode === 'yearly'}
                                  />
                              </div>
                          </div>

                          <div className="space-y-1">
                              <div className="flex justify-between text-xs text-gray-500">
                                  <span>Spent: {spent.toLocaleString()}</span>
                                  <span className={catRemaining < 0 ? 'text-red-400' : 'text-emerald-400'}>
                                      {catRemaining >= 0 ? 'Left: ' : 'Over: '} {Math.abs(catRemaining).toLocaleString()}
                                  </span>
                              </div>
                              <div className="h-1.5 bg-gray-800 rounded-full overflow-hidden">
                                  <div 
                                    className={`h-full rounded-full transition-all duration-500 ${catPercent > 100 ? 'bg-red-500' : 'bg-blue-500'}`} 
                                    style={{ width: `${Math.min(catPercent, 100)}%` }}
                                  />
                              </div>
                          </div>
                      </div>
                  );
              })}
              {activeAccounts.length === 0 && <div className="text-gray-500 text-sm col-span-full text-center py-10">No categories selected. Click settings to add some.</div>}
          </div>
      </div>

      <Modal isOpen={isManageOpen} onClose={() => setIsManageOpen(false)} title="Manage Budget Categories">
          <div className="space-y-2 max-h-[60vh] overflow-y-auto pr-2">
              {allExpenseAccounts.map(cat => (
                  <div key={cat.id} className="flex items-center justify-between p-3 bg-gray-900 rounded-xl border border-gray-800 hover:bg-gray-800 cursor-pointer" onClick={() => handleVisibleToggle(cat.id)}>
                      <div className="flex items-center gap-3">
                          <span className="text-sm font-medium text-gray-200">{cat.name}</span>
                      </div>
                      {visibleAccountIds.includes(cat.id) 
                        ? <CheckSquare size={20} className="text-primary" /> 
                        : <Square size={20} className="text-gray-600" />
                      }
                  </div>
              ))}
          </div>
      </Modal>

      {/* Copy Budget Modal */}
      <Modal isOpen={isCopyModalOpen} onClose={() => setIsCopyModalOpen(false)} title="Copy Budget">
          <form onSubmit={handleCopyBudget} className="space-y-6">
              <div className="p-4 bg-blue-900/10 border border-blue-500/20 rounded-xl">
                  <p className="text-xs text-blue-300 font-bold uppercase tracking-wider mb-1">Source</p>
                  <p className="text-white font-medium flex items-center gap-2">
                      <Calendar size={16} />
                      {format(selectedDate, 'MMMM yyyy')}
                  </p>
                  <p className="text-xs text-gray-400 mt-2">
                      This will overwrite the budget for the target selected below.
                  </p>
              </div>

              <div>
                  <label className="text-xs text-gray-500 font-bold uppercase tracking-wider mb-2 block">Target Type</label>
                  <div className="grid grid-cols-2 gap-3">
                      <button 
                          type="button"
                          onClick={() => { setCopyTargetType('single'); setCopyTargetValue(''); }}
                          className={`py-3 px-4 rounded-xl border text-sm font-bold transition-all ${copyTargetType === 'single' ? 'bg-primary border-primary text-white' : 'bg-gray-900 border-gray-700 text-gray-400 hover:bg-gray-800'}`}
                      >
                          Single Month
                      </button>
                      <button 
                          type="button"
                          onClick={() => { setCopyTargetType('year'); setCopyTargetValue(''); }}
                          className={`py-3 px-4 rounded-xl border text-sm font-bold transition-all ${copyTargetType === 'year' ? 'bg-primary border-primary text-white' : 'bg-gray-900 border-gray-700 text-gray-400 hover:bg-gray-800'}`}
                      >
                          Full Year
                      </button>
                  </div>
              </div>

              <div>
                  <label className="text-xs text-gray-500 font-bold uppercase tracking-wider mb-2 block">
                      {copyTargetType === 'single' ? 'Select Target Month' : 'Select Target Year'}
                  </label>
                  {copyTargetType === 'single' ? (
                      <input 
                          type="month" 
                          className="w-full px-4 py-3 bg-gray-900 border border-gray-700 rounded-xl text-white outline-none focus:border-primary"
                          value={copyTargetValue}
                          onChange={e => setCopyTargetValue(e.target.value)}
                          required
                      />
                  ) : (
                      <input 
                          type="number" 
                          min="2020" max="2100"
                          placeholder="YYYY"
                          className="w-full px-4 py-3 bg-gray-900 border border-gray-700 rounded-xl text-white outline-none focus:border-primary"
                          value={copyTargetValue}
                          onChange={e => setCopyTargetValue(e.target.value)}
                          required
                      />
                  )}
              </div>

              <button 
                  type="submit"
                  className="w-full py-3 bg-gradient-to-r from-primary to-blue-600 hover:from-blue-600 hover:to-primary text-white font-bold rounded-xl shadow-lg transition-all active:scale-95"
              >
                  Copy Budget
              </button>
          </form>
      </Modal>
    </div>
  );
};

import React, { useMemo, useState } from 'react';
import { useFinance } from '../context/FinanceContext';
import { usePWA } from '../context/PWAContext';
import { Wallet, Briefcase, CreditCard, Clock, ChevronDown, ChevronUp, CheckSquare, Square, ArrowDownLeft, ArrowUpRight, ArrowRightLeft, Download, Share, PlusSquare, Monitor, Smartphone, TrendingUp } from 'lucide-react';
import { format, parseISO, startOfMonth, endOfMonth, isWithinInterval, startOfYear, endOfYear, endOfDay, isAfter } from 'date-fns';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip as RechartsTooltip } from 'recharts';
import { useNavigate } from 'react-router-dom';
import { Modal } from '../components/ui/Modal';

export const Dashboard: React.FC = () => {
  const { state } = useFinance();
  const { isInstallable, installPWA, isIOS } = usePWA();
  const navigate = useNavigate();
  const [showProfitDetails, setShowProfitDetails] = useState(false);
  const [checkedAssets, setCheckedAssets] = useState<Record<string, boolean>>({});
  const [showIOSInstruction, setShowIOSInstruction] = useState(false);
  const [showGenericInstruction, setShowGenericInstruction] = useState(false);
  const [includeDirectCosts, setIncludeDirectCosts] = useState(false);

  const currency = state.businessProfile.baseCurrency || 'QAR';

  React.useEffect(() => {
      // Default Ticked: Cash & Equivalents usually.
      const cashGroup = state.accounts.find(a => a.code === '11100');
      const cashGroupId = cashGroup?.id;

      // Filter specifically for Cash accounts (Children of 11100 or Code 111xx)
      const cashAccounts = state.accounts.filter(c => 
          c.isPosting && (
              (cashGroupId && c.parentId === cashGroupId) || 
              c.code.startsWith('111')
          )
      );

      const initial: Record<string, boolean> = {};
      cashAccounts.forEach(c => {
          initial[c.id] = true;
      });
      setCheckedAssets(prev => Object.keys(prev).length === 0 ? initial : prev);
  }, [state.accounts]);

  const handleInstallClick = async () => {
      if (isIOS) {
          setShowIOSInstruction(true);
      } else {
          const promptShown = await installPWA();
          if (!promptShown) {
             setShowGenericInstruction(true);
          }
      }
  };

  const currentMonthKey = format(new Date(), 'yyyy-MM');
  const currentYearKey = format(new Date(), 'yyyy');
  const monthStart = startOfMonth(new Date());
  const monthEnd = endOfMonth(new Date());
  const yearStart = startOfYear(new Date());
  const yearEnd = endOfYear(new Date());

  // Cutoff for "Current" state - Include everything up to the very end of today
  const endOfToday = endOfDay(new Date());

  const txsInMonth = useMemo(() => state.transactions.filter(t => {
      const d = parseISO(t.date);
      // Include if in month range AND not in the future (Month-to-Date view)
      return isWithinInterval(d, { start: monthStart, end: monthEnd }) && d <= endOfToday;
  }), [state.transactions]);

  const txsInYear = useMemo(() => state.transactions.filter(t => {
      const d = parseISO(t.date);
      return isWithinInterval(d, { start: yearStart, end: yearEnd }) && d <= endOfToday;
  }), [state.transactions]);

  // --- 1. Cash Breakdown ---
  const assetBalances = useMemo(() => {
      const balances: Record<string, { name: string, amount: number, id: string, code?: string }> = {};

      // Target Account: 11100 - Cash & Cash Equivalents
      const cashGroup = state.accounts.find(a => a.code === '11100');
      const cashGroupId = cashGroup?.id;

      // Initialize with only Cash & Cash Equivalents accounts
      state.accounts.filter(c => 
          c.isPosting && (
              (cashGroupId && c.parentId === cashGroupId) || 
              c.code.startsWith('111')
          )
      ).forEach(c => {
          balances[c.id] = { name: c.name, amount: 0, id: c.id, code: c.code };
      });

      state.transactions.forEach(t => {
          // Strict Date Filter: Do not include future transactions in Cash Balance
          if (parseISO(t.date) > endOfToday) return;

          // Standard Debit Normal logic for Assets
          // Debit increases (t.accountId), Credit decreases (t.paymentAccountId)
          if (t.accountId && balances[t.accountId]) {
              balances[t.accountId].amount += t.amount; 
          }
          if (t.paymentAccountId && balances[t.paymentAccountId]) {
              balances[t.paymentAccountId].amount -= t.amount; 
          }
      });

      return Object.values(balances)
        .sort((a,b) => (parseInt(a.code || '0') - parseInt(b.code || '0')));
  }, [state.transactions, state.accounts]);

  const totalSelectedCash = assetBalances.reduce((sum, a) => checkedAssets[a.id] ? sum + a.amount : sum, 0);

  // --- 2. Payables & Receivables ---
  // Filter out future/unearned items from Dashboard Totals
  const pendingReceivables = state.receivables.filter(r => 
      r.type === 'receivable' && 
      r.status === 'pending' &&
      (!r.issueDate || parseISO(r.issueDate) <= endOfToday)
  );
  // Subtract paidAmount for correct outstanding balance
  const totalReceivables = pendingReceivables.reduce((acc, curr) => acc + (curr.amount - (curr.paidAmount || 0)), 0);

  const pendingPayables = state.receivables.filter(r => 
      r.type === 'payable' && 
      r.status === 'pending' &&
      (!r.issueDate || parseISO(r.issueDate) <= endOfToday)
  );
  // Subtract paidAmount for correct outstanding balance
  const totalPayables = pendingPayables.reduce((acc, curr) => acc + (curr.amount - (curr.paidAmount || 0)), 0);

  // --- 3. Budget & Profit ---
  const budgetObjMonth = state.monthlyBudgets?.find(b => b.monthKey === currentMonthKey);
  const currentMonthBudget = budgetObjMonth?.limit || 0;
  const visibleCatIdsMonth = budgetObjMonth?.visibleAccountIds || [];
  const totalExpensesMonth = txsInMonth
    .filter(t => t.type === 'expense' && (budgetObjMonth ? visibleCatIdsMonth.includes(t.accountId) : true))
    .reduce((s, t) => s + t.amount, 0);
  const budgetProgressMonth = currentMonthBudget > 0 ? (totalExpensesMonth / currentMonthBudget) * 100 : 0;

  // -- YEARLY AGGREGATION --
  const aggregatedYearlyBudget = useMemo(() => {
      let totalLimit = 0;
      const allVisibleAccountIds = new Set<string>();

      // Iterate through all 12 months of the current year
      for (let i = 1; i <= 12; i++) {
          const monthKey = `${currentYearKey}-${String(i).padStart(2, '0')}`;
          const monthBudget = state.monthlyBudgets?.find(b => b.monthKey === monthKey);

          if (monthBudget) {
              totalLimit += monthBudget.limit;
              if (monthBudget.visibleAccountIds) {
                  monthBudget.visibleAccountIds.forEach(id => allVisibleAccountIds.add(id));
              }
          }
      }

      return {
          limit: totalLimit,
          visibleAccountIds: Array.from(allVisibleAccountIds)
      };
  }, [state.monthlyBudgets, currentYearKey]);

  const currentYearBudget = aggregatedYearlyBudget.limit;
  const visibleCatIdsYear = aggregatedYearlyBudget.visibleAccountIds;
  const totalExpensesYear = txsInYear
    .filter(t => t.type === 'expense' && (visibleCatIdsYear.length > 0 ? visibleCatIdsYear.includes(t.accountId) : true))
    .reduce((s, t) => s + t.amount, 0);
  const budgetProgressYear = currentYearBudget > 0 ? (totalExpensesYear / currentYearBudget) * 100 : 0;

  const bizStats = useMemo(() => {
      let revenue = 0;
      let cogs = 0;
      let expenses = 0;

      txsInMonth.forEach(t => {
          // Identify accounts involved
          const debitAcc = state.accounts.find(c => c.id === t.accountId);
          const creditAcc = state.accounts.find(c => c.id === t.paymentAccountId);

          // 1. Check for Revenue (Usually Credited)
          if (creditAcc?.class === 'Revenue') {
              revenue += t.amount;
          }
          // Handle Returns/Refunds (Debited Revenue)
          if (debitAcc?.class === 'Revenue') {
              revenue -= t.amount;
          }

          // 2. Check for Expenses (Usually Debited)
          if (debitAcc?.class === 'Expenses') {
              // Heuristic: Check if code suggests COGS (50000 range) or OpEx (60000 range)
              if (debitAcc.code.startsWith('5')) cogs += t.amount;
              else expenses += t.amount;
          }
          // Handle Refunds/Reversals (Credited Expense)
          if (creditAcc?.class === 'Expenses') {
              if (creditAcc.code.startsWith('5')) cogs -= t.amount;
              else expenses -= t.amount;
          }
      });

      // Use absolute values
      const absRevenue = Math.abs(revenue);
      const absCogs = Math.abs(cogs);
      const absExpenses = Math.abs(expenses);

      return { 
          revenue: absRevenue, 
          cogs: absCogs, 
          expenses: absExpenses, 
          gross: absRevenue - absCogs, 
          net: absRevenue - absCogs - absExpenses 
      };
  }, [txsInMonth, state.accounts]);

  // --- 4. Charts ---
  const expenseData = useMemo(() => {
      const map: Record<string, number> = {};
      txsInMonth.filter(t => t.type === 'expense').forEach(t => {
          const acc = state.accounts.find(c => c.id === t.accountId);
          if (!acc) return;

          // Exclude COGS if toggle is off
          // COGS accounts start with '5' in this schema (50000 range)
          if (!includeDirectCosts && acc.code.startsWith('5')) return;

          const catName = acc.name;
          map[catName] = (map[catName] || 0) + t.amount;
      });
      return Object.entries(map).map(([name, value]) => ({ name, value })).sort((a,b) => b.value - a.value).slice(0, 5);
  }, [txsInMonth, state.accounts, includeDirectCosts]);

  const COLORS = ['#ef4444', '#f97316', '#f59e0b', '#8b5cf6', '#3b82f6'];
  const recentTxs = [...state.transactions]
    .filter(t => parseISO(t.date) <= endOfToday) // Filter out future transactions
    .sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime())
    .slice(0, 5);

  return (
    <div className="space-y-6 pb-24 md:pb-0 animate-slide-up">
      <div className="flex justify-between items-end">
          <div>
            <h1 className="text-3xl font-bold text-white tracking-tight">Dashboard</h1>
            <p className="text-gray-400 text-sm">{format(new Date(), 'MMMM yyyy')}</p>
          </div>
          {/* SMALL INSTALL BUTTON IN HEADER */}
          {isInstallable && (
              <button 
                  onClick={handleInstallClick}
                  className="flex items-center gap-2 bg-gray-800 hover:bg-gray-700 text-gold-400 border border-gold-500/30 px-3 py-1.5 rounded-lg text-xs font-bold transition-all hover:scale-105 active:scale-95"
                  title="Install App"
              >
                  <Download size={14} />
                  <span className="hidden sm:inline">Install App</span>
              </button>
          )}
      </div>

      {/* --- ROW 1: CASH & PROFIT --- */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {/* CASH BREAKDOWN */}
          <div className="glass-card p-5 rounded-2xl relative overflow-hidden bg-gray-900 border border-gold-500/10 hover:border-gold-500/30 hover:-translate-y-1 hover:shadow-2xl transition-all duration-300 group">
              <div className="flex justify-between items-start mb-4">
                  <h3 className="text-gray-400 text-xs font-bold uppercase tracking-widest flex items-center gap-2"><Wallet size={14} className="text-gold-500 group-hover:scale-110 transition-transform"/> Cash and Cash Equivalent </h3>
                  <span className="text-2xl font-bold text-white group-hover:text-gold-400 transition-colors">{currency} {totalSelectedCash.toLocaleString()}</span>
              </div>
              <div className="space-y-2 max-h-40 overflow-y-auto pr-2 custom-scrollbar">
                  {assetBalances.map(acc => (
                      <div key={acc.id} className="flex items-center justify-between p-2 rounded-lg bg-gray-950/50 border border-white/5 cursor-pointer hover:bg-gray-800/80 transition-colors" onClick={() => setCheckedAssets(prev => ({...prev, [acc.id]: !prev[acc.id]}))}>
                          <div className="flex items-center gap-2">
                              {checkedAssets[acc.id] ? <CheckSquare size={16} className="text-gold-500"/> : <Square size={16} className="text-gray-600"/>}
                              <span className="text-sm text-gray-300">
                                {acc.code ? `${acc.code} - ` : ''}{acc.name}
                              </span>
                          </div>
                          <span className={`text-sm font-mono ${acc.amount < 0 ? 'text-red-400' : 'text-emerald-400'}`}>{acc.amount.toLocaleString()}</span>
                      </div>
                  ))}
              </div>
          </div>

          {/* BUSINESS PROFIT CARD (GROSS ONLY) */}
          <div className="glass-card p-5 rounded-2xl bg-gray-900 border border-blue-500/10 cursor-pointer transition-all duration-300 hover:border-blue-500/40 hover:-translate-y-1 hover:shadow-2xl group" onClick={() => setShowProfitDetails(!showProfitDetails)}>
              <div className="flex justify-between items-start">
                  <div>
                      <p className="text-gray-400 text-xs font-bold uppercase tracking-widest flex items-center gap-2"><Briefcase size={14} className="text-blue-500 group-hover:scale-110 transition-transform"/> Business Performance</p>
                      <h3 className={`text-3xl font-bold mt-2 ${bizStats.gross >= 0 ? 'text-blue-400' : 'text-red-400'}`}>
                          {currency} {bizStats.gross.toLocaleString()}
                      </h3>
                      <div className="flex items-center gap-2 mt-2">
                          <span className="text-xs text-gray-500 font-bold">GROSS PROFIT (Rev - Direct Cost)</span>
                      </div>
                  </div>
                  {showProfitDetails ? <ChevronUp className="text-gray-500"/> : <ChevronDown className="text-gray-500"/>}
              </div>

              {showProfitDetails && (
                  <div className="mt-4 pt-4 border-t border-white/10 space-y-2 animate-fade-in">
                      <div className="flex justify-between text-sm"><span className="text-gray-400">Revenue</span><span className="text-emerald-400">+ {bizStats.revenue.toLocaleString()}</span></div>
                      <div className="flex justify-between text-sm"><span className="text-gray-400">Direct Costs</span><span className="text-orange-400">- {bizStats.cogs.toLocaleString()}</span></div>
                      <div className="mt-2 text-xs text-center text-gray-500 bg-gray-950/50 py-1 rounded">
                          Margin: {bizStats.revenue > 0 ? (bizStats.gross / bizStats.revenue * 100).toFixed(1) : 0}%
                      </div>
                  </div>
              )}
          </div>
      </div>

      {/* --- ROW 2: SMALLER CARDS + BUDGET --- */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <div className="glass-card p-4 rounded-xl border-l-4 border-l-emerald-500 flex flex-col justify-between hover:bg-gray-800/50 hover:shadow-lg transition-all duration-200 cursor-pointer active:scale-95" onClick={() => navigate('/apar')}>
              <div className="flex justify-between items-start">
                  <div>
                    <p className="text-[10px] font-bold text-emerald-500 uppercase">Receivables</p>
                    <p className="text-lg font-bold text-white mt-1">{currency} {totalReceivables.toLocaleString()}</p>
                  </div>
                  <ArrowDownLeft size={16} className="text-emerald-500 opacity-50"/>
              </div>
              <div className="mt-2 text-[10px] text-gray-500">{pendingReceivables.length} Active</div>
          </div>

          <div className="glass-card p-4 rounded-xl border-l-4 border-l-orange-500 flex flex-col justify-between hover:bg-gray-800/50 hover:shadow-lg transition-all duration-200 cursor-pointer active:scale-95" onClick={() => navigate('/apar')}>
             <div className="flex justify-between items-start">
                  <div>
                      <p className="text-[10px] font-bold text-orange-500 uppercase">Payables</p>
                      <p className="text-lg font-bold text-white mt-1">{currency} {totalPayables.toLocaleString()}</p>
                  </div>
                  <ArrowUpRight size={16} className="text-orange-500 opacity-50"/>
              </div>
              <div className="mt-2 text-[10px] text-gray-500">{pendingPayables.length} Active</div>
          </div>

          <div className="md:col-span-2 glass-card p-4 rounded-xl flex flex-col justify-center gap-3 hover:border-gray-600 transition-colors">
             <div>
                <div className="flex justify-between text-[10px] uppercase font-bold text-gray-500 mb-1">
                    <span>Monthly Budget</span>
                    <span>{budgetProgressMonth.toFixed(0)}%</span>
                </div>
                <div className="h-2 bg-gray-800 rounded-full overflow-hidden">
                    <div className={`h-full transition-all duration-1000 ${budgetProgressMonth > 100 ? 'bg-red-500' : 'bg-blue-500'}`} style={{ width: `${Math.min(budgetProgressMonth, 100)}%` }}></div>
                </div>
             </div>
             <div>
                <div className="flex justify-between text-[10px] uppercase font-bold text-gray-500 mb-1">
                    <span>Yearly Budget</span>
                    <span>{budgetProgressYear.toFixed(0)}%</span>
                </div>
                <div className="h-2 bg-gray-800 rounded-full overflow-hidden">
                    <div className={`h-full transition-all duration-1000 ${budgetProgressYear > 100 ? 'bg-red-500' : 'bg-purple-500'}`} style={{ width: `${Math.min(budgetProgressYear, 100)}%` }}></div>
                </div>
             </div>
          </div>
      </div>

      {/* --- ROW 3: CHARTS & HISTORY --- */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          <div className="glass-card rounded-2xl p-5 border border-white/5 hover:border-white/10 transition-colors">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-gray-400 text-xs font-bold uppercase">Top 5 Expenses</h3>
                <button 
                    onClick={() => setIncludeDirectCosts(!includeDirectCosts)}
                    className={`text-[10px] px-2 py-1 rounded transition-colors border ${includeDirectCosts ? 'bg-blue-500/20 text-blue-400 border-blue-500/30' : 'bg-gray-800 text-gray-500 border-gray-700 hover:text-gray-300'}`}
                >
                    {includeDirectCosts ? 'With Direct Costs' : 'No Direct Costs'}
                </button>
              </div>
              <div className="h-[200px] w-full flex items-center justify-center">
                <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                        <Pie data={expenseData} cx="50%" cy="50%" innerRadius={40} outerRadius={70} paddingAngle={5} dataKey="value" stroke="none">
                            {expenseData.map((entry, index) => (
                                <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                            ))}
                        </Pie>
                        <RechartsTooltip contentStyle={{ backgroundColor: '#111827', borderColor: '#374151', fontSize: '12px' }} itemStyle={{ color: '#fff' }} formatter={(val: number) => `${currency} ${val.toLocaleString()}`} />
                    </PieChart>
                </ResponsiveContainer>
              </div>
              <div className="flex flex-wrap gap-2 justify-center mt-2">
                  {expenseData.map((e, i) => (
                      <div key={e.name} className="flex items-center gap-1 text-[10px] text-gray-400">
                          <div className="w-2 h-2 rounded-full" style={{ background: COLORS[i % COLORS.length] }} />
                          {e.name}
                      </div>
                  ))}
              </div>
          </div>

          <div className="lg:col-span-2 glass-card rounded-2xl p-5 border border-white/5 hover:border-white/10 transition-colors">
              <h3 className="text-gray-400 text-xs font-bold uppercase mb-4 flex items-center gap-2"><Clock size={14}/> Recent Activity</h3>
              <div className="space-y-3">
                  {recentTxs.map(t => {
                      const acc = state.accounts.find(c => c.id === t.accountId);
                      let sign = '-';
                      let colorClass = 'text-gray-300';
                      let iconBg = 'bg-gray-800 text-gray-400';

                      if (t.type === 'income') {
                          sign = '+';
                          colorClass = 'text-emerald-400';
                          iconBg = 'bg-emerald-500/10 text-emerald-400';
                      } else if (t.type === 'transfer') {
                          sign = '↔';
                          colorClass = 'text-blue-400';
                          iconBg = 'bg-blue-500/10 text-blue-400';
                      }

                      return (
                          <div key={t.id} className="flex items-center justify-between p-3 bg-gray-950/30 rounded-xl border border-white/5 hover:bg-gray-800/50 hover:translate-x-1 transition-all">
                              <div className="flex items-center gap-3">
                                  <div className={`p-2 rounded-lg ${iconBg}`}>
                                      {t.type === 'income' ? <TrendingUp size={16}/> : (t.type === 'transfer' ? <ArrowRightLeft size={16}/> : <CreditCard size={16}/>)}
                                  </div>
                                  <div>
                                      <p className="text-sm font-medium text-gray-200">{acc?.name || 'Unknown'}</p>
                                      <p className="text-[10px] text-gray-500">{format(parseISO(t.date), 'MMM d')} • {t.note || '-'}</p>
                                  </div>
                              </div>
                              <span className={`font-mono text-sm font-bold ${colorClass}`}>
                                  {sign} {t.amount.toLocaleString()}
                              </span>
                          </div>
                      );
                  })}
                  {recentTxs.length === 0 && <p className="text-center text-gray-600 py-4 text-sm">No recent transactions.</p>}
              </div>
          </div>
      </div>

      {/* iOS Instructions Modal */}
      <Modal isOpen={showIOSInstruction} onClose={() => setShowIOSInstruction(false)} title="Install on iPhone/iPad">
         <div className="p-4 space-y-4 text-gray-300">
             <p className="text-sm">This app can be installed on your home screen for a full-screen experience and offline access.</p>
             <div className="space-y-3">
                 <div className="flex items-center gap-3">
                     <div className="p-2 bg-gray-800 rounded"><Share size={20} className="text-blue-400"/></div>
                     <span className="text-sm">1. Tap the <b>Share</b> button in Safari toolbar.</span>
                 </div>
                 <div className="flex items-center gap-3">
                     <div className="p-2 bg-gray-800 rounded"><PlusSquare size={20} className="text-gray-400"/></div>
                     <span className="text-sm">2. Scroll down and tap <b>Add to Home Screen</b>.</span>
                 </div>
             </div>
             <button onClick={() => setShowIOSInstruction(false)} className="w-full py-3 bg-gray-800 hover:bg-gray-700 rounded-xl mt-4 text-sm font-bold">Got it</button>
         </div>
      </Modal>

      {/* Generic Instructions Modal (Chrome/Android Fallback) */}
      <Modal isOpen={showGenericInstruction} onClose={() => setShowGenericInstruction(false)} title="Install App">
            <div className="p-4 space-y-4 text-gray-300">
            <p className="text-sm">To install the app, use your browser's menu.</p>

            <div className="space-y-3">
                <div className="flex items-start gap-3">
                    <div className="p-2 bg-gray-800 rounded text-gray-400"><Monitor size={20} /></div>
                    <div>
                        <strong className="text-sm text-white block">Desktop (Chrome/Edge)</strong>
                        <span className="text-xs text-gray-500">Click the install icon <Download size={10} className="inline"/> in the address bar (right side).</span>
                    </div>
                </div>
                    <div className="flex items-start gap-3">
                    <div className="p-2 bg-gray-800 rounded text-gray-400"><Smartphone size={20} /></div>
                    <div>
                        <strong className="text-sm text-white block">Android (Chrome)</strong>
                        <span className="text-xs text-gray-500">Tap <span className="font-bold">⋮</span> (Menu) and select <b>Install App</b> or <b>Add to Home Screen</b>.</span>
                    </div>
                </div>
            </div>

            <button onClick={() => setShowGenericInstruction(false)} className="w-full py-3 bg-gray-800 hover:bg-gray-700 rounded-xl mt-4 text-sm font-bold">Close</button>
            </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useFinance } from '../context/FinanceContext';
import { Receivable, Transaction, CurrencyCode, RecurrenceFrequency } from '../types';
import { EXCHANGE_RATE_QAR_TO_PHP } from '../constants';
import { format, isPast, addDays, addWeeks, addMonths, addYears, parseISO, endOfDay } from 'date-fns';
import { Plus, CheckCircle, ArrowUpRight, ArrowDownLeft, Repeat, Pencil, Trash2, HandCoins, FileText, Filter, Copy, RefreshCw, Users, Info } from 'lucide-react';
import { Modal } from '../components/ui/Modal';
import { SearchableSelect } from '../components/ui/SearchableSelect';
import { evaluateMathExpression } from '../utils/mathUtils';
import { InvoiceModal } from '../components/InvoiceModal';
import { useNavigate, useLocation } from 'react-router-dom';

type Mode = 'receivable' | 'payable';
type SubMode = 'invoice' | 'bill' | 'loan';

export const ApAr: React.FC = () => {
  const { state, dispatch } = useFinance();
  const navigate = useNavigate();
  const location = useLocation();
  const [activeTab, setActiveTab] = useState<'all' | 'receivable' | 'payable'>('all');

  // Modals
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
  const [invoiceData, setInvoiceData] = useState<Receivable | null>(null);

  // Selection
  const [selectedItem, setSelectedItem] = useState<Receivable | null>(null);

  // Form State
  const [formMode, setFormMode] = useState<Mode>('receivable');
  const [formSubMode, setFormSubMode] = useState<SubMode>('invoice');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [partyId, setPartyId] = useState('');
  const [targetAccountId, setTargetAccountId] = useState('');
  const [amount, setAmount] = useState('');
  const [currency, setCurrency] = useState<CurrencyCode>('QAR');

  const baseCurrency = state.businessProfile.baseCurrency || 'QAR';

  // Fix: Use local YYYY-MM-DD for default to prevent "yesterday" bugs
  const getTodayLocal = () => {
      const d = new Date();
      const year = d.getFullYear();
      const month = String(d.getMonth() + 1).padStart(2, '0');
      const day = String(d.getDate()).padStart(2, '0');
      return `${year}-${month}-${day}`;
  };
  const [issueDate, setIssueDate] = useState('');
  const [dueDate, setDueDate] = useState('');

  const [notes, setNotes] = useState('');
  const [isRecurring, setIsRecurring] = useState(false);
  const [recurFreq, setRecurFreq] = useState<RecurrenceFrequency>('monthly');

  // Payment State
  const [paymentAccountId, setPaymentAccountId] = useState('');
  const [paymentAmount, setPaymentAmount] = useState('');

  // Handle Navigation Shortcuts
  useEffect(() => {
      if (location.state) {
          const { openMode, openSubMode } = location.state as any;
          if (openMode && openSubMode) {
              handleOpenAdd(openMode, openSubMode);
              // Clear state to avoid reopening on refresh/back
              window.history.replaceState({}, document.title);
          }
      }
  }, [location]);

  // --- HELPERS ---

  const getPartyOptions = () => {
    // Show ALL parties to allow flexibility (Requirement 2)
    // Add subLabel to distinguish types
    return state.parties.map(p => ({ 
        id: p.id, 
        label: p.name,
        subLabel: p.type.charAt(0).toUpperCase() + p.type.slice(1) // Capitalize type
    }));
  };

  const getAccountOptions = (mode: Mode, subMode: SubMode) => {
    // Only allow Sub-Ledgers
    const subLedgers = state.accounts.filter(a => a.level === 'sub_ledger' && a.isPosting);

    if (mode === 'receivable') {
        if (subMode === 'loan') {
            // Money leaving Bank (Credit Asset)
            return subLedgers.filter(a => a.class === 'Assets').map(a => ({ id: a.id, label: a.name, subLabel: a.code }));
        }
        // Revenue (Credit Revenue)
        return subLedgers.filter(a => a.class === 'Revenue').map(a => ({ id: a.id, label: a.name, subLabel: a.code }));
    } else {
        if (subMode === 'loan') {
             // Money entering Bank (Debit Asset)
             return subLedgers.filter(a => a.class === 'Assets').map(a => ({ id: a.id, label: a.name, subLabel: a.code }));
        }
        // Expense (Debit Expense)
        return subLedgers.filter(a => a.class === 'Expenses' || a.class === 'Liabilities').map(a => ({ id: a.id, label: a.name, subLabel: a.code }));
    }
  };

  // Only allow Cash & Cash Equivalents (111xx)
  const cashGroup = state.accounts.find(a => a.code === '11100');
  const cashOptions = state.accounts
      .filter(a => 
          a.isPosting && 
          (
              a.code.startsWith('111') || 
              (cashGroup && a.parentId === cashGroup.id)
          )
      )
      .map(a => ({ id: a.id, label: a.name, subLabel: a.code }));

  // --- ACTIONS ---

  const goToPartySOA = (partyId: string) => {
      const party = state.parties.find(p => p.id === partyId);
      if (party?.linkedAccountId) {
          navigate('/reports', { state: { tab: 'soa', accountId: party.linkedAccountId } });
      } else {
          alert("This party is not linked to a specific sub-ledger account.");
      }
  };

  const handleOpenAdd = (mode: Mode, subMode: SubMode) => {
      resetForm();
      setFormMode(mode);
      setFormSubMode(subMode);

      // Auto-select bank for loans (if it is a sub ledger)
      if (subMode === 'loan') {
          const bank = state.accounts.find(c => c.class === 'Assets' && c.level === 'sub_ledger' && c.name.toLowerCase().includes('bank'));
          if (bank) setTargetAccountId(bank.id);
      }

      setIsFormOpen(true);
  };

  const handleOpenEdit = (item: Receivable) => {
      setEditingId(item.id);
      setFormMode(item.type);
      setFormSubMode(item.subType || (item.type === 'receivable' ? 'invoice' : 'bill'));
      setPartyId(item.partyId || '');
      setTargetAccountId(item.targetAccountId || '');
      setAmount((item.originalAmount || item.amount).toString());
      setCurrency(item.currency || 'QAR');
      setIssueDate(item.issueDate ? item.issueDate.split('T')[0] : getTodayLocal());
      setDueDate(item.dueDate.split('T')[0]);
      setNotes(item.notes || '');
      setIsRecurring(!!item.recurring?.active);
      setRecurFreq(item.recurring?.frequency || 'monthly');
      setIsFormOpen(true);
  };

  const handleSave = (e: React.FormEvent) => {
      e.preventDefault();
      const finalValStr = evaluateMathExpression(amount);
      const val = parseFloat(finalValStr);
      if (isNaN(val) || !partyId || !targetAccountId) {
          alert("Please fill all required fields correctly.");
          return;
      }

      const finalAmountQAR = currency === 'PHP' ? val / EXCHANGE_RATE_QAR_TO_PHP : val;
      const party = state.parties.find(p => p.id === partyId);
      const newId = editingId || Math.random().toString(36).substr(2, 9);

      const validIssueDate = issueDate ? new Date(issueDate).toISOString() : new Date().toISOString();

      const payload: Receivable = {
          id: newId,
          type: formMode,
          subType: formSubMode,
          partyId,
          partyName: party?.name || 'Unknown',
          targetAccountId,
          amount: finalAmountQAR,
          paidAmount: 0,
          originalAmount: val,
          currency,
          issueDate: validIssueDate,
          dueDate: new Date(dueDate).toISOString(),
          status: 'pending',
          notes,
          recurring: isRecurring ? { active: true, amount: val, frequency: recurFreq, nextDueDate: dueDate } : undefined
      };

      if (editingId) {
          // Preserve existing payments on edit
          const existing = state.receivables.find(r => r.id === editingId);
          payload.paidAmount = existing?.paidAmount || 0;
          if (payload.paidAmount >= payload.amount) payload.status = 'paid';
          dispatch({ type: 'UPDATE_RECEIVABLE', payload });
      } else {
          dispatch({ type: 'ADD_RECEIVABLE', payload });
          createAccrualTransaction(payload, newId);
      }
      setIsFormOpen(false);
  };

  const createAccrualTransaction = (item: Receivable, id: string) => {
      // Logic to create the underlying GL transaction
      const party = state.parties.find(p => p.id === item.partyId);
      const partyLinkedAccount = party?.linkedAccountId;

      if (!partyLinkedAccount) {
          console.warn("Party has no linked account for accrual posting.");
          return;
      }

      // Identify if this is a Loan (Cash Movement) or Accrual (Invoice/Bill)
      const isLoan = item.subType === 'loan';
      const txType = isLoan ? 'transfer' : (item.type === 'receivable' ? 'income' : 'expense');
      const txNote = isLoan ? `Disbursement: ${item.subType} Ref:${id}` : `Accrual: ${item.subType} Ref:${id}`;

      const tx: Transaction = {
          id: Math.random().toString(36).substr(2, 9),
          date: item.issueDate || new Date().toISOString(), // Use provided issue date
          currency: item.currency,
          amount: item.amount,
          originalAmount: item.originalAmount,
          relatedPartyId: item.partyId,
          source: isLoan ? 'personal' : (item.type === 'receivable' ? 'side_hustle' : 'personal'),
          note: txNote, 
          type: txType,

          accountId: item.type === 'receivable' 
            ? partyLinkedAccount // Dr Party AR (Asset)
            : (isLoan ? item.targetAccountId : item.targetAccountId), // Dr Bank or Expense

          paymentAccountId: item.type === 'receivable'
            ? item.targetAccountId // Cr Bank (for Loan) or Revenue
            : partyLinkedAccount // Cr Party AP
      };

      dispatch({ type: 'ADD_TRANSACTION', payload: tx });
  };

  const handleSync = () => {
      const confirmSync = confirm("Reconcile Transactions?\n\nThis will scan all active Payables/Receivables and create missing GL transactions if they were accidentally deleted.");
      if (!confirmSync) return;

      let createdCount = 0;
      state.receivables.forEach(r => {
          const exists = state.transactions.some(t => t.note?.includes(`Ref:${r.id}`));
          if (!exists) {
              createAccrualTransaction(r, r.id);
              createdCount++;
          }
      });

      alert(createdCount > 0 ? `Synced! Created ${createdCount} missing transactions.` : "All records are in sync.");
  };

  const handleDelete = (id: string) => {
      if(confirm("Delete this record? Associated Journal Entries will be removed.")) {
          dispatch({ type: 'DELETE_RECEIVABLE', payload: id });
      }
  };

  const handleOpenPayment = (item: Receivable) => {
      setSelectedItem(item);
      const bank = cashOptions.find(c => c.label.toLowerCase().includes('bank')) || cashOptions[0];
      setPaymentAccountId(bank ? bank.id : '');

      // Default to remaining balance
      const remaining = item.amount - (item.paidAmount || 0);
      setPaymentAmount(remaining.toString());

      setIsPaymentModalOpen(true);
  };

  const handleProcessPayment = (e: React.FormEvent) => {
      e.preventDefault();
      if (!selectedItem || !paymentAccountId) return;

      const payValStr = evaluateMathExpression(paymentAmount);
      const payVal = parseFloat(payValStr);
      if (isNaN(payVal) || payVal <= 0) {
          alert("Please enter a valid amount.");
          return;
      }

      const item = selectedItem;
      const currentPaid = item.paidAmount || 0;
      const newPaidTotal = currentPaid + payVal;
      const isFullyPaid = newPaidTotal >= (item.amount - 0.01); // Tolerance for float math

      // Update Receivable Record
      const updatedItem: Receivable = {
          ...item,
          paidAmount: newPaidTotal,
          status: isFullyPaid ? 'paid' : 'pending',
          paidDate: isFullyPaid ? new Date().toISOString() : undefined
      };
      dispatch({ type: 'UPDATE_RECEIVABLE', payload: updatedItem });

      // Create Payment Transaction (Partial Amount)
      const party = state.parties.find(p => p.id === item.partyId);
      const partyLinkedAccount = party?.linkedAccountId;

      const isLoan = item.subType === 'loan';
      const txType = isLoan ? 'transfer' : (item.type === 'receivable' ? 'income' : 'expense');

      const tx: Transaction = {
          id: Math.random().toString(36).substr(2, 9),
          date: new Date().toISOString(),
          currency: item.currency,
          amount: payVal, // Use partial amount for GL
          originalAmount: payVal, // Assuming same currency base for simplicity or 1:1 if QAR
          relatedPartyId: item.partyId,
          source: isLoan ? 'personal' : (item.type === 'receivable' ? 'side_hustle' : 'personal'),
          note: `Settlement (${isFullyPaid ? 'Full' : 'Partial'}): ${item.subType} Ref:${item.id}`,
          type: txType,
          accountId: item.type === 'receivable' ? paymentAccountId : (partyLinkedAccount || ''),
          paymentAccountId: item.type === 'receivable' ? (partyLinkedAccount || '') : paymentAccountId
      };

      if (partyLinkedAccount) {
         dispatch({ type: 'ADD_TRANSACTION', payload: tx });
      }

      // Handle Recurring - ONLY if Fully Paid (or if user wants auto-recurrence on settlement)
      // Logic: Only generate next item if we are fully setting the current one.
      if (isFullyPaid && item.recurring?.active) {
          const freq = item.recurring.frequency;

          const dueStr = item.dueDate.split('T')[0];
          const baseDueDate = new Date(dueStr + 'T00:00:00.000Z');
          let nextDueDate = baseDueDate;

          if (freq === 'daily') nextDueDate = addDays(baseDueDate, 1);
          if (freq === 'weekly') nextDueDate = addWeeks(baseDueDate, 1);
          if (freq === 'monthly') nextDueDate = addMonths(baseDueDate, 1);
          if (freq === 'yearly') nextDueDate = addYears(baseDueDate, 1);

          const issueStr = item.issueDate ? item.issueDate.split('T')[0] : dueStr;
          const baseIssueDate = new Date(issueStr + 'T00:00:00.000Z');
          let nextIssueDate = baseIssueDate;

          if (freq === 'daily') nextIssueDate = addDays(baseIssueDate, 1);
          if (freq === 'weekly') nextIssueDate = addWeeks(baseIssueDate, 1);
          if (freq === 'monthly') nextIssueDate = addMonths(baseIssueDate, 1);
          if (freq === 'yearly') nextIssueDate = addYears(baseIssueDate, 1);

          const nextId = Math.random().toString(36).substr(2, 9);
          const nextItem: Receivable = {
              ...item,
              id: nextId,
              dueDate: nextDueDate.toISOString(),
              status: 'pending',
              paidDate: undefined,
              paidAmount: 0,
              issueDate: nextIssueDate.toISOString() 
          };
          dispatch({ type: 'ADD_RECEIVABLE', payload: nextItem });

          if (item.subType === 'invoice' || item.subType === 'bill') {
              const nextTxType = item.type === 'receivable' ? 'income' : 'expense';
              const nextAccrualTx: Transaction = {
                  id: Math.random().toString(36).substr(2, 9),
                  date: nextIssueDate.toISOString(), 
                  currency: item.currency,
                  amount: item.amount,
                  originalAmount: item.originalAmount,
                  relatedPartyId: item.partyId,
                  source: 'side_hustle',
                  note: `Accrual (Auto): ${item.subType} Ref:${nextId}`,
                  type: nextTxType,
                  accountId: item.type === 'receivable' ? (partyLinkedAccount || '') : item.targetAccountId,
                  paymentAccountId: item.type === 'receivable' ? item.targetAccountId : (partyLinkedAccount || '')
              };
              if (partyLinkedAccount) {
                  dispatch({ type: 'ADD_TRANSACTION', payload: nextAccrualTx });
              }
          }
      }

      setIsPaymentModalOpen(false);
  };

  const resetForm = () => {
      setEditingId(null); setPartyId(''); setTargetAccountId(''); setAmount(''); setNotes(''); setIsRecurring(false); 
      setIssueDate(getTodayLocal());
      setDueDate('');
  };

  // --- RENDER ---
  const filteredList = state.receivables.filter(item => {
      if (item.status === 'paid') return false; 
      if (activeTab === 'all') return true;
      return item.type === activeTab;
  }).sort((a,b) => new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime());

  const todayEnd = endOfDay(new Date());

  const totalAr = state.receivables.filter(r => 
      r.type === 'receivable' && 
      r.status === 'pending' &&
      (!r.issueDate || parseISO(r.issueDate) <= todayEnd)
  ).reduce((s, r) => s + (r.amount - (r.paidAmount || 0)), 0);

  const totalAp = state.receivables.filter(r => 
      r.type === 'payable' && 
      r.status === 'pending' &&
      (!r.issueDate || parseISO(r.issueDate) <= todayEnd)
  ).reduce((s, r) => s + (r.amount - (r.paidAmount || 0)), 0);

  return (
    <div className="space-y-6 pb-20 md:pb-0 animate-fade-in">
        {/* Header & Tabs - Unchanged */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div><h1 className="text-3xl font-bold text-gray-100 tracking-tight">AP / AR</h1><p className="text-gray-400 text-sm">Manage invoices, bills, and loans</p></div>
            <div className="flex gap-2 flex-wrap">
                <button onClick={() => navigate('/settings', { state: { tab: 'parties' } })} className="flex items-center gap-2 bg-gray-800 hover:bg-gray-700 text-gray-400 px-3 py-2 rounded-xl text-xs font-bold uppercase transition-all hover:scale-105"><Users size={16} /> Parties</button>
                <button onClick={handleSync} className="flex items-center gap-2 bg-gray-800 hover:bg-gray-700 text-gray-400 px-3 py-2 rounded-xl text-xs font-bold uppercase transition-all hover:scale-105"><RefreshCw size={16} /> Sync</button>
                <button onClick={() => handleOpenAdd('receivable', 'invoice')} className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-3 py-2 rounded-xl text-xs font-bold uppercase transition-all hover:scale-105 active:scale-95"><Plus size={16} /> New Invoice</button>
                <button onClick={() => handleOpenAdd('payable', 'bill')} className="flex items-center gap-2 bg-orange-600 hover:bg-orange-700 text-white px-3 py-2 rounded-xl text-xs font-bold uppercase transition-all hover:scale-105 active:scale-95"><Plus size={16} /> New Bill</button>
                <button onClick={() => handleOpenAdd('receivable', 'loan')} className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-3 py-2 rounded-xl text-xs font-bold uppercase transition-all hover:scale-105 active:scale-95"><HandCoins size={16} /> Loan</button>
            </div>
        </div>

        {/* Summary Cards - Updated Calculation */}
        <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
            <div className="bg-emerald-900/20 border border-emerald-500/30 p-4 rounded-2xl hover:-translate-y-1 hover:shadow-lg transition-all duration-300">
                <p className="text-xs font-bold text-emerald-400 uppercase mb-1">Total Receivables</p>
                <p className="text-2xl font-bold text-white">{baseCurrency} {totalAr.toLocaleString()}</p>
                <div className="mt-2 text-[10px] text-gray-400">Current Outstanding</div>
            </div>
            <div className="bg-orange-900/20 border border-orange-500/30 p-4 rounded-2xl hover:-translate-y-1 hover:shadow-lg transition-all duration-300">
                <p className="text-xs font-bold text-orange-400 uppercase mb-1">Total Payables</p>
                <p className="text-2xl font-bold text-white">{baseCurrency} {totalAp.toLocaleString()}</p>
                <div className="mt-2 text-[10px] text-gray-400">Current Outstanding</div>
            </div>
             <div className="bg-gray-900/40 border border-gray-800 p-4 rounded-2xl hidden md:block hover:bg-gray-800 transition-colors">
                <p className="text-xs font-bold text-gray-400 uppercase mb-1">Net Position</p>
                <p className={`text-2xl font-bold ${(totalAr - totalAp) >= 0 ? 'text-blue-400' : 'text-red-400'}`}>{baseCurrency} {(totalAr - totalAp).toLocaleString()}</p>
                <div className="mt-2 text-[10px] text-gray-500">Current Impact</div>
            </div>
        </div>

        {/* Tabs & List - Unchanged */}
        <div className="flex border-b border-gray-800">
             <button onClick={() => setActiveTab('all')} className={`px-6 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'all' ? 'border-primary text-white' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>All Pending</button>
             <button onClick={() => setActiveTab('receivable')} className={`px-6 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'receivable' ? 'border-emerald-500 text-emerald-400' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>Receivables</button>
             <button onClick={() => setActiveTab('payable')} className={`px-6 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'payable' ? 'border-orange-500 text-orange-400' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>Payables</button>
        </div>

        <div className="grid gap-4">
            {filteredList.map(item => {
                const isOverdue = isPast(new Date(item.dueDate));
                const isFutureItem = item.issueDate && parseISO(item.issueDate) > todayEnd;
                const colorClass = item.type === 'receivable' ? 'text-emerald-400' : 'text-orange-400';
                const bgClass = item.type === 'receivable' ? 'bg-emerald-500/10' : 'bg-orange-500/10';
                const icon = item.subType === 'loan' ? <HandCoins size={20}/> : (item.type === 'receivable' ? <ArrowDownLeft size={20}/> : <ArrowUpRight size={20}/>);
                const accName = state.accounts.find(c => c.id === item.targetAccountId)?.name;
                const remaining = item.amount - (item.paidAmount || 0);

                return (
                    <div key={item.id} className={`glass-panel p-5 rounded-xl flex flex-col sm:flex-row sm:items-center justify-between gap-4 group hover:bg-gray-800/60 hover:-translate-y-1 hover:shadow-xl transition-all duration-300 ${isFutureItem ? 'opacity-60 grayscale-[0.5]' : ''}`}>
                        <div className="flex items-start gap-4">
                             <div className={`p-3 rounded-xl shrink-0 ${bgClass} ${colorClass}`}>{icon}</div>
                             <div>
                                 <div className="flex items-center gap-2">
                                     <h3 className="font-bold text-gray-200">{item.partyName}</h3>
                                     {item.partyId && <button onClick={() => goToPartySOA(item.partyId!)} className="p-1 hover:bg-gray-700 rounded text-gray-500 hover:text-blue-400 transition-colors"><FileText size={14} /></button>}
                                     {item.recurring?.active && <Repeat size={14} className="text-blue-400" />}
                                     <span className={`text-[10px] px-1.5 py-0.5 rounded font-bold uppercase ${item.type === 'receivable' ? 'bg-emerald-900/30 text-emerald-400' : 'bg-orange-900/30 text-orange-400'}`}>{item.subType}</span>
                                     {isFutureItem && <span className="text-[10px] px-1.5 py-0.5 rounded font-bold uppercase bg-gray-700 text-gray-300">Future</span>}
                                 </div>
                                 <p className="text-sm text-gray-400">{item.notes}</p>
                                 <div className="flex items-center gap-3 mt-1.5"><span className={`text-xs ${isOverdue ? 'text-red-400 font-bold' : 'text-gray-500'}`}>Due {format(new Date(item.dueDate), 'MMM d')}</span><span className="text-xs text-gray-600">• {accName}</span></div>
                             </div>
                        </div>
                        <div className="flex items-center justify-between sm:justify-end gap-6 w-full sm:w-auto border-t sm:border-t-0 border-gray-800 pt-3 sm:pt-0">
                             <div className="text-right">
                                 {item.paidAmount && item.paidAmount > 0 ? (
                                     <span className="block text-[10px] text-gray-500 mb-0.5 font-mono">
                                         PAID: {item.paidAmount.toLocaleString()} / {item.amount.toLocaleString()}
                                     </span>
                                 ) : null}
                                 <span className={`block text-xl font-bold ${colorClass}`}>{item.type === 'receivable' ? '+' : '-'} {remaining.toLocaleString()}</span>
                                 {item.currency === 'PHP' && <span className="text-xs text-gray-500">₱{item.originalAmount?.toLocaleString()}</span>}
                             </div>
                             <div className="flex gap-1 opacity-80 group-hover:opacity-100 transition-opacity">
                                 <button onClick={() => handleOpenPayment(item)} className={`p-2 rounded-lg transition-all active:scale-90 ${item.type === 'receivable' ? 'bg-emerald-600/20 text-emerald-400 hover:bg-emerald-600/40' : 'bg-orange-600/20 text-orange-400 hover:bg-orange-600/40'}`} title="Settle"><CheckCircle size={18} /></button>
                                 <button onClick={() => handleOpenEdit(item)} className="p-2 text-gray-500 hover:text-white hover:bg-gray-800 rounded-lg active:scale-90 transition-all"><Pencil size={18}/></button>
                                 <button onClick={() => handleDelete(item.id)} className="p-2 text-gray-500 hover:text-red-400 hover:bg-gray-800 rounded-lg active:scale-90 transition-all"><Trash2 size={18}/></button>
                                 {item.type === 'receivable' && item.subType !== 'loan' && <button onClick={() => setInvoiceData(item)} className="p-2 text-gray-500 hover:text-blue-400 hover:bg-gray-800 rounded-lg active:scale-90 transition-all"><FileText size={18}/></button>}
                             </div>
                        </div>
                    </div>
                );
            })}
            {filteredList.length === 0 && <div className="text-center py-12 text-gray-500 border border-dashed border-gray-800 rounded-xl">No active records found.</div>}
        </div>

        {/* Form Modal - Unchanged */}
        <Modal isOpen={isFormOpen} onClose={() => setIsFormOpen(false)} title={`${editingId ? 'Edit' : 'New'} ${formSubMode.charAt(0).toUpperCase() + formSubMode.slice(1)}`}>
            <form onSubmit={handleSave} className="space-y-4">
                <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Entity</label>
                    <SearchableSelect options={getPartyOptions()} value={partyId} onChange={setPartyId} required placeholder="Select Name..." />
                </div>
                <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">{formMode === 'receivable' ? 'Revenue / Source Account' : 'Expense / Asset Account'}</label>
                    <SearchableSelect options={getAccountOptions(formMode, formSubMode)} value={targetAccountId} onChange={setTargetAccountId} required placeholder="Select Account..." />
                </div>
                <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Amount</label>
                    <div className="flex gap-2">
                        <input type="text" inputMode="decimal" className="flex-1 px-4 py-2 bg-gray-900 border border-gray-700 rounded-xl text-white outline-none focus:border-primary" value={amount} onChange={e => setAmount(e.target.value)} onBlur={() => setAmount(evaluateMathExpression(amount))} placeholder="0.00" required />
                        <select className="w-24 px-2 bg-gray-950 border border-gray-700 rounded-xl text-white outline-none" value={currency} onChange={e => setCurrency(e.target.value as CurrencyCode)}><option value="QAR">QAR</option><option value="PHP">PHP</option></select>
                    </div>
                    {/* Math Toolbar */}
                    <div className="flex gap-2 mt-2 overflow-x-auto no-scrollbar pb-1">
                        {['+', '-', '*', '/', '(', ')'].map(op => (
                            <button
                                key={op}
                                type="button"
                                tabIndex={-1}
                                onMouseDown={(e) => e.preventDefault()}
                                onClick={() => setAmount(prev => prev + op)}
                                className="flex-1 min-w-[40px] h-10 bg-gray-800 hover:bg-gray-700 text-gold-400 font-bold rounded-lg border border-gray-700 flex items-center justify-center text-lg active:scale-95 transition-transform"
                            >
                                {op === '*' ? '×' : op === '/' ? '÷' : op}
                            </button>
                        ))}
                    </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div>
                         <label className="block text-xs font-bold text-gray-500 uppercase mb-1">{formMode === 'receivable' ? 'Revenue/Issue Date' : 'Expense/Bill Date'}</label>
                         <input type="date" className="w-full px-4 py-2 bg-gray-900 border border-gray-700 rounded-xl text-white outline-none focus:border-primary" value={issueDate} onChange={e => setIssueDate(e.target.value)} required />
                    </div>
                    <div>
                         <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Due Date</label>
                         <input type="date" className="w-full px-4 py-2 bg-gray-900 border border-gray-700 rounded-xl text-white outline-none focus:border-primary" value={dueDate} onChange={e => setDueDate(e.target.value)} required />
                    </div>
                </div>
                <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Recurrence</label>
                    <div className="flex items-center gap-2 h-[42px] px-3 bg-gray-900 border border-gray-700 rounded-xl">
                        <input type="checkbox" checked={isRecurring} onChange={e => setIsRecurring(e.target.checked)} className="w-4 h-4 bg-gray-800 border-gray-600 rounded" />
                        <select disabled={!isRecurring} value={recurFreq} onChange={e => setRecurFreq(e.target.value as RecurrenceFrequency)} className="bg-transparent text-xs text-white outline-none disabled:opacity-50"><option value="monthly">Monthly</option><option value="weekly">Weekly</option><option value="yearly">Yearly</option></select>
                    </div>
                </div>
                <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Notes</label>
                    <input type="text" className="w-full px-4 py-2 bg-gray-900 border border-gray-700 rounded-xl text-white outline-none focus:border-primary" value={notes} onChange={e => setNotes(e.target.value)} placeholder="Description..." />
                </div>
                <button className={`w-full py-3 rounded-xl font-bold text-white shadow-lg transition-transform active:scale-[0.98] ${formMode === 'receivable' ? 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-900/20' : 'bg-orange-600 hover:bg-orange-700 shadow-orange-900/20'}`}>Save Record</button>
            </form>
        </Modal>

        {/* Payment Modal - Updated for Partial Payment */}
        <Modal isOpen={isPaymentModalOpen} onClose={() => setIsPaymentModalOpen(false)} title={`Settle ${selectedItem?.type === 'receivable' ? 'Invoice' : 'Bill'}`}>
             <form onSubmit={handleProcessPayment} className="space-y-4">
                <div className="p-4 bg-gray-900/50 rounded-xl mb-4 border border-gray-800">
                    <div className="flex justify-between text-sm text-gray-500 mb-1">
                        <span>Total Amount</span>
                        <span>{selectedItem?.amount.toLocaleString()}</span>
                    </div>
                    <div className="flex justify-between text-sm text-gray-500 mb-3 border-b border-gray-700 pb-3">
                        <span>Paid So Far</span>
                        <span>- {(selectedItem?.paidAmount || 0).toLocaleString()}</span>
                    </div>
                    <div className="flex justify-between items-center">
                        <span className="text-gray-300 font-bold uppercase text-xs">Remaining Balance</span>
                        <span className="text-2xl font-bold text-white">{baseCurrency} {(selectedItem ? (selectedItem.amount - (selectedItem.paidAmount || 0)) : 0).toLocaleString()}</span>
                    </div>
                </div>

                <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Amount to {selectedItem?.type === 'receivable' ? 'Receive' : 'Pay'}</label>
                    <input 
                        type="text" 
                        inputMode="decimal"
                        className="w-full px-4 py-3 bg-gray-900 border border-gray-700 rounded-xl text-white outline-none focus:border-primary font-bold text-lg" 
                        value={paymentAmount} 
                        onChange={e => setPaymentAmount(e.target.value)} 
                        onBlur={() => setPaymentAmount(evaluateMathExpression(paymentAmount))}
                        placeholder="0.00" 
                        required 
                    />
                    {/* Math Toolbar */}
                    <div className="flex gap-2 mt-2 overflow-x-auto no-scrollbar pb-1">
                        {['+', '-', '*', '/', '(', ')'].map(op => (
                            <button
                                key={op}
                                type="button"
                                tabIndex={-1}
                                onMouseDown={(e) => e.preventDefault()}
                                onClick={() => setPaymentAmount(prev => prev + op)}
                                className="flex-1 min-w-[40px] h-10 bg-gray-800 hover:bg-gray-700 text-gold-400 font-bold rounded-lg border border-gray-700 flex items-center justify-center text-lg active:scale-95 transition-transform"
                            >
                                {op === '*' ? '×' : op === '/' ? '÷' : op}
                            </button>
                        ))}
                    </div>
                </div>

                <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">{selectedItem?.type === 'receivable' ? 'Deposit To (Debit)' : 'Pay From (Credit)'}</label>
                    <SearchableSelect options={cashOptions} value={paymentAccountId} onChange={setPaymentAccountId} required placeholder="Select Cash/Bank..." />
                </div>

                <div className="flex items-center gap-2 text-xs text-blue-400 bg-blue-900/10 p-3 rounded-lg border border-blue-500/20">
                    <Info size={14} />
                    <span>Transaction will be recorded for the entered amount only. Item remains pending until fully paid.</span>
                </div>

                <button className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold shadow-lg shadow-blue-900/20">Confirm Transaction</button>
             </form>
        </Modal>

        {invoiceData && <InvoiceModal isOpen={!!invoiceData} onClose={() => setInvoiceData(null)} data={invoiceData} appState={state} />}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { useFinance } from '../context/FinanceContext';
import { TransactionType, SourceType, Transaction, CurrencyCode, RecurrenceFrequency, RecurringTransaction, TransactionTemplate } from '../types';
import { CURRENCIES } from '../constants';
import { Check, ArrowRightLeft, LayoutGrid, List, Save, ArrowRight, Repeat, Star, Tag } from 'lucide-react';
import { addDays, addMonths, addWeeks, addYears } from 'date-fns';
import { SearchableSelect } from './ui/SearchableSelect';
import { evaluateMathExpression } from '../utils/mathUtils';
import { useNavigate } from 'react-router-dom';

interface TransactionFormProps {
  onComplete: () => void;
  initialType?: TransactionType;
  initialData?: Transaction | null;
  mode?: 'transaction' | 'template';
  onSaveTemplate?: (template: TransactionTemplate) => void;
  initialTemplate?: TransactionTemplate | null;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ 
    onComplete, 
    initialType = 'expense', 
    initialData, 
    mode = 'transaction',
    onSaveTemplate,
    initialTemplate
}) => {
  const { state, dispatch } = useFinance();
  const navigate = useNavigate();
  const baseCurrency = state.businessProfile.baseCurrency || 'USD';

  // Ref for the submit button to support NumpadEnter shortcut
  const submitBtnRef = useRef<HTMLButtonElement>(null);

  // Helper for Local YYYY-MM-DD
  const getTodayLocal = () => {
      const d = new Date();
      const year = d.getFullYear();
      const month = String(d.getMonth() + 1).padStart(2, '0');
      const day = String(d.getDate()).padStart(2, '0');
      return `${year}-${month}-${day}`;
  };

  // Template specific state
  const [templateName, setTemplateName] = useState(initialTemplate?.name || '');
  const [templateIcon, setTemplateIcon] = useState(initialTemplate?.icon || '⚡');

  // Shared state
  const [type, setType] = useState<TransactionType>(initialData?.type || initialType);
  const [amount, setAmount] = useState(
      initialData ? (initialData.originalAmount || initialData.amount).toString() : 
      (initialTemplate ? (initialTemplate.amount || '').toString() : '')
  );

  // Default currency to Base Currency if not provided
  const [currency, setCurrency] = useState<CurrencyCode>(initialData?.currency || initialTemplate?.currency || baseCurrency);

  const [accountId, setAccountId] = useState(initialData?.accountId || initialTemplate?.accountId || '');
  const [source, setSource] = useState<SourceType>(initialData?.source || initialTemplate?.source || 'personal');
  const [paymentAccountId, setPaymentAccountId] = useState(initialData?.paymentAccountId || initialTemplate?.paymentAccountId || '');
  // Fix: Use local date for default to avoid timezone shift errors
  const [date, setDate] = useState(initialData ? initialData.date.split('T')[0] : getTodayLocal());
  const [note, setNote] = useState(initialData?.note || initialTemplate?.note || '');
  const [partyId, setPartyId] = useState(initialData?.relatedPartyId || initialTemplate?.partyId || '');

  // Recurrence State (Transaction Mode Only)
  const [isRecurring, setIsRecurring] = useState(false);
  const [recurFreq, setRecurFreq] = useState<RecurrenceFrequency>('monthly');

  const [viewMode, setViewMode] = useState<'form' | 'pos'>('pos');

  useEffect(() => {
    if (initialData || initialTemplate || mode === 'template') {
        setViewMode('form');

        // Infer Type from Account Class for Templates if not explicit
        if (mode === 'template' && accountId) {
             const acc = state.accounts.find(a => a.id === accountId);
             if (acc) {
                 if (acc.class === 'Revenue' || acc.class === 'Equity') setType('income');
                 else if (acc.class === 'Expenses' || acc.class === 'Liabilities') setType('expense');
             }
        }

        // Logic to swap UI fields for Income if editing existing data
        if (initialData && initialData.type === 'income' && !state.accounts.find(a => a.id === initialData.accountId)?.class.includes('Revenue')) {
             setAccountId(initialData.paymentAccountId || '');
             setPaymentAccountId(initialData.accountId);
        }
    } else {
        const isMobile = window.innerWidth < 768;
        if(isMobile) setViewMode('pos');
    }
  }, [initialData, initialTemplate, state.accounts, mode]);

  // Handle NumpadEnter Shortcut
  useEffect(() => {
      const handleKeyDown = (e: KeyboardEvent) => {
          if (e.code === 'NumpadEnter') {
              e.preventDefault(); // Prevent newline in textareas or other default behaviors
              if (submitBtnRef.current) {
                  submitBtnRef.current.click();
              }
          }
      };
      window.addEventListener('keydown', handleKeyDown);
      return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  // AUTO-SET DEFAULT PAYMENT ACCOUNT
  useEffect(() => {
      if (initialData || initialTemplate) return; 
      // Only auto-select if it's a Sub-Ledger. 
      const bank = state.accounts.find(c => c.class === 'Assets' && c.name.toLowerCase().includes('bank') && c.level === 'sub_ledger');
      const cash = state.accounts.find(c => c.class === 'Assets' && c.name.toLowerCase().includes('cash') && c.level === 'sub_ledger');

      if (type === 'expense') {
          if (bank) setPaymentAccountId(bank.id);
      } else if (type === 'income') {
          if (cash) setPaymentAccountId(cash.id);
      } else if (type === 'transfer') {
          if (bank) setPaymentAccountId(bank.id);
      }
  }, [type, state.accounts, initialData, initialTemplate]);

  // DATA TRANSFORMATION FOR SEARCHABLE SELECT
  const availableAccounts = state.accounts
      .filter(c => {
          if (!c.isPosting) return false;
          // Removed strict sub_ledger check to allow GL accounts (like default Bank/Cash) to be selected
          // if (c.level !== 'sub_ledger') return false; 

          if (type === 'transfer') return true; 

          if (type === 'expense') return c.class === 'Expenses' || c.class === 'Liabilities' || c.class === 'Assets'; 
          if (type === 'income') return c.class === 'Revenue' || c.class === 'Equity';

          return true;
      })
      .sort((a, b) => {
          const codeA = parseInt(a.code) || 99999;
          const codeB = parseInt(b.code) || 99999;
          return codeA - codeB || a.name.localeCompare(b.name);
      })
      .map(c => ({
          id: c.id,
          label: c.name,
          subLabel: c.code
      }));

  const availableParties = state.parties
      .filter(e => e.type === (type === 'income' ? 'customer' : 'vendor'))
      .map(e => ({ id: e.id, label: e.name }));

  const transferSourceAccounts = state.accounts
      .filter(c => {
          if (!c.isPosting) return false;
          // Removed strict sub_ledger check
          // if (c.level !== 'sub_ledger') return false;

          if (type === 'transfer') return true;
          return c.class === 'Assets'; 
      })
      .sort((a, b) => {
          const codeA = parseInt(a.code) || 99999;
          const codeB = parseInt(b.code) || 99999;
          return codeA - codeB || a.name.localeCompare(b.name);
      })
      .map(c => ({
          id: c.id,
          label: c.name,
          subLabel: c.code
      }));

  // Organize Currencies: Base Currency first, then others
  const sortedCurrencies = [...CURRENCIES].sort((a, b) => {
      if (a.code === baseCurrency) return -1;
      if (b.code === baseCurrency) return 1;
      return a.code.localeCompare(b.code);
  });

  const selectedCurrencySymbol = CURRENCIES.find(c => c.code === currency)?.symbol || '$';

  const handleAccountChange = (id: string) => {
    setAccountId(id);
  };

  const handleTemplateClick = (templateId: string) => {
      const t = state.templates.find(temp => temp.id === templateId);
      if(!t) return;

      const acc = state.accounts.find(c => c.id === t.accountId);
      if(acc) {
        const targetType = (acc.class === 'Assets' || acc.class === 'Liabilities') ? 'expense' : (acc.class === 'Revenue' ? 'income' : 'expense');
        setType(targetType as TransactionType);
        setAccountId(acc.id);
        if (t.source) setSource(t.source);
      }

      if(t.amount) setAmount(t.amount.toString());
      setCurrency(t.currency);
      if(t.note) setNote(t.note);
      if(t.partyId) setPartyId(t.partyId);
      if(t.paymentAccountId) setPaymentAccountId(t.paymentAccountId);

      setViewMode('form'); 
  };

  const handleAmountBlur = () => {
      setAmount(evaluateMathExpression(amount));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalAmountStr = evaluateMathExpression(amount);

    if (!finalAmountStr && mode === 'transaction') return; // Amount mandatory for transaction
    if (!accountId) { alert('Please select a main category/account.'); return; }

    if (type === 'transfer' && !paymentAccountId) {
        alert("Please select a 'From' account.");
        return;
    }
    if (type === 'transfer' && accountId === paymentAccountId) {
        alert("From and To accounts cannot be the same.");
        return;
    }

    const inputAmount = parseFloat(finalAmountStr) || 0;

    // NOTE: In a real multi-currency system, we would ask for exchange rate if Currency != BaseCurrency.
    // For now, we assume direct entry relative to Base Currency or user handles conversion logic via input expression.

    const finalAmountBase = inputAmount; 

    // --- CRITICAL ACCOUNTING LOGIC ---
    let finalDebitAccount = accountId;
    let finalCreditAccount = paymentAccountId;

    if (type === 'income') {
        finalDebitAccount = paymentAccountId; // Bank becomes Dr
        finalCreditAccount = accountId;      // Revenue becomes Cr
    } 

    // --- TEMPLATE SAVE MODE ---
    if (mode === 'template') {
        if (!templateName) { alert('Please name your shortcut.'); return; }
        const templateData: TransactionTemplate = {
            id: initialTemplate?.id || Math.random().toString(36).substr(2, 9),
            name: templateName,
            icon: templateIcon,
            accountId: accountId, // Store the user selected account ID (Category), not the resolved debit/credit
            amount: inputAmount || undefined, // Optional in template
            currency: currency,
            note: note,
            partyId: partyId || undefined,
            paymentAccountId: paymentAccountId || undefined,
            source: source
        };
        if (onSaveTemplate) onSaveTemplate(templateData);
        onComplete();
        return;
    }

    // --- TRANSACTION SAVE MODE ---
    if (isNaN(inputAmount) || inputAmount <= 0) {
        alert("Invalid amount");
        return;
    }

    const transactionData: Transaction = {
      id: initialData?.id || Math.random().toString(36).substr(2, 9),
      date: new Date(date).toISOString(),
      type,
      amount: finalAmountBase, // This should technically be the converted amount to base
      originalAmount: inputAmount,
      currency: currency,
      accountId: finalDebitAccount, // DEBIT
      source,
      paymentAccountId: finalCreditAccount || undefined, // CREDIT
      note,
      relatedPartyId: partyId || undefined
    };

    if (initialData) {
        dispatch({ type: 'UPDATE_TRANSACTION', payload: transactionData });
    } else {
        dispatch({ type: 'ADD_TRANSACTION', payload: transactionData });

        if (isRecurring) {
            // STRICT DATE CALCULATION
            const baseDate = new Date(date + 'T00:00:00.000Z');
            let nextDate = baseDate;

            if (recurFreq === 'daily') nextDate = addDays(baseDate, 1);
            if (recurFreq === 'weekly') nextDate = addWeeks(baseDate, 1);
            if (recurFreq === 'monthly') nextDate = addMonths(baseDate, 1);
            if (recurFreq === 'yearly') nextDate = addYears(baseDate, 1);

            const recurringRule: RecurringTransaction = {
                id: Math.random().toString(36).substr(2, 9),
                active: true,
                type,
                accountId: finalDebitAccount,
                amount: finalAmountBase,
                originalAmount: inputAmount,
                currency,
                source,
                paymentAccountId: finalCreditAccount || undefined,
                partyId: partyId || undefined,
                note: note,
                frequency: recurFreq,
                nextDueDate: nextDate.toISOString()
            };

            dispatch({ type: 'ADD_RECURRING', payload: recurringRule });
            // Use local string for alert to be friendly
            alert(`Recurring rule created. Next due: ${nextDate.toISOString().split('T')[0]}`);
        }
    }
    onComplete();
  };

  return (
    <div className="space-y-4">
        {!initialData && mode === 'transaction' && (
            <div className="flex justify-end mb-2">
                <button 
                    onClick={() => setViewMode(viewMode === 'form' ? 'pos' : 'form')}
                    className="text-xs flex items-center gap-1.5 text-primary hover:text-blue-400 font-bold px-4 py-2.5 bg-gray-800 rounded-xl border border-gray-700 glass-card btn-float active:scale-95"
                >
                    {viewMode === 'form' ? <><LayoutGrid size={16} /> Use Shortcuts</> : <><List size={16} /> Manual Entry</>}
                </button>
            </div>
        )}

        {viewMode === 'pos' && !initialData && mode === 'transaction' ? (
            <div className="grid grid-cols-2 gap-3 max-h-[60vh] overflow-y-auto no-scrollbar pb-4">
                {state.templates.length === 0 && (
                    <div className="col-span-2 text-center py-12 text-gray-500 text-sm border border-dashed border-gray-700 rounded-2xl flex flex-col items-center gap-3">
                        <LayoutGrid size={32} className="opacity-20" />
                        <div>No shortcuts configured.<br/>Add them in Settings.</div>
                    </div>
                )}
                {state.templates.map(t => {
                    const tSym = CURRENCIES.find(c => c.code === t.currency)?.symbol || '$';
                    return (
                        <button
                            key={t.id}
                            onClick={() => handleTemplateClick(t.id)}
                            className="flex flex-col items-center justify-center p-5 bg-gray-800/60 backdrop-blur-md border border-gray-700 hover:border-primary hover:bg-gray-800/80 rounded-2xl transition-all active:scale-95 btn-float group"
                        >
                            <span className="text-4xl mb-3 group-hover:scale-110 transition-transform">{t.icon || '⚡'}</span>
                            <span className="text-sm font-bold text-gray-100 tracking-tight">{t.name}</span>
                            {t.amount && (
                            <span className="text-[10px] text-gold-500/80 font-mono mt-1 px-1.5 py-0.5 bg-gold-500/5 rounded border border-gold-500/10">
                                {tSym}{t.amount.toLocaleString()}
                            </span>
                            )}
                        </button>
                    );
                })}
            </div>
        ) : (
            <form onSubmit={handleSubmit} className="space-y-5 animate-fade-in">

                {/* QUICK SHORTCUTS FOR ACCRUALS */}
                {mode === 'transaction' && !initialData && (
                    <div className="grid grid-cols-3 gap-3 mb-2">
                        <button 
                            type="button" 
                            onClick={() => {
                                onComplete();
                                navigate('/apar', { state: { openMode: 'receivable', openSubMode: 'invoice' } });
                            }} 
                            className="flex items-center justify-center py-2.5 rounded-xl text-xs font-bold uppercase tracking-widest bg-gradient-to-br from-emerald-500/10 to-teal-600/10 hover:from-emerald-500/30 hover:to-teal-600/30 border border-emerald-500/20 hover:border-emerald-500/50 text-emerald-400 transition-all active:scale-95 shadow-lg shadow-emerald-900/5 backdrop-blur-md"
                        >
                            AR
                        </button>
                        <button 
                            type="button" 
                            onClick={() => {
                                onComplete();
                                navigate('/apar', { state: { openMode: 'payable', openSubMode: 'bill' } });
                            }} 
                            className="flex items-center justify-center py-2.5 rounded-xl text-xs font-bold uppercase tracking-widest bg-gradient-to-br from-red-500/10 to-orange-600/10 hover:from-red-500/30 hover:to-orange-600/30 border border-red-500/20 hover:border-red-500/50 text-red-400 transition-all active:scale-95 shadow-lg shadow-red-900/5 backdrop-blur-md"
                        >
                            AP
                        </button>
                        <button 
                            type="button" 
                            onClick={() => {
                                onComplete();
                                navigate('/apar', { state: { openMode: 'receivable', openSubMode: 'loan' } });
                            }} 
                            className="flex items-center justify-center py-2.5 rounded-xl text-xs font-bold uppercase tracking-widest bg-gradient-to-br from-purple-500/10 to-indigo-600/10 hover:from-purple-500/30 hover:to-indigo-600/30 border border-purple-500/20 hover:border-purple-500/50 text-purple-400 transition-all active:scale-95 shadow-lg shadow-purple-900/5 backdrop-blur-md"
                        >
                            P
                        </button>
                    </div>
                )}

                {/* TEMPLATE HEADER FIELDS */}
                {mode === 'template' && (
                    <div className="bg-indigo-900/20 p-4 rounded-xl border border-indigo-500/30 space-y-4 mb-2">
                        <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-widest flex items-center gap-2">
                            <Star size={14} /> Shortcut Details
                        </h4>
                        <div>
                            <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Shortcut Name</label>
                            <input 
                                type="text" 
                                value={templateName} 
                                onChange={e => setTemplateName(e.target.value)} 
                                className="w-full px-4 py-2.5 bg-gray-950 text-white border border-gray-700 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none" 
                                placeholder="e.g. Morning Coffee"
                                autoFocus
                            />
                        </div>
                        <div>
                            <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Icon / Emoji</label>
                            <div className="flex gap-2">
                                {['⚡','☕','⛽','🛒','🍔','🚗','🏠','💊','✈️','🎓'].map(icon => (
                                    <button 
                                        type="button" 
                                        key={icon} 
                                        onClick={() => setTemplateIcon(icon)}
                                        className={`w-10 h-10 rounded-lg flex items-center justify-center text-xl transition-colors ${templateIcon === icon ? 'bg-indigo-600 text-white' : 'bg-gray-800 text-gray-400 hover:bg-gray-700'}`}
                                    >
                                        {icon}
                                    </button>
                                ))}
                                <input 
                                    type="text" 
                                    value={templateIcon} 
                                    onChange={e => setTemplateIcon(e.target.value)} 
                                    className="w-12 h-10 text-center bg-gray-950 border border-gray-700 rounded-lg text-white" 
                                    placeholder="?"
                                />
                            </div>
                        </div>
                    </div>
                )}

                <div className="grid grid-cols-3 gap-2 p-1.5 bg-gray-900/50 rounded-2xl border border-gray-700">
                    <button type="button" onClick={() => { setType('expense'); setPartyId(''); }} className={`py-3 text-xs font-bold uppercase tracking-widest rounded-xl transition-all ${type === 'expense' ? 'bg-gray-700 text-red-400 shadow-lg shadow-black/20 ring-1 ring-white/10' : 'text-gray-500 hover:text-gray-300'}`}>Expense</button>
                    <button type="button" onClick={() => { setType('income'); setPartyId(''); }} className={`py-3 text-xs font-bold uppercase tracking-widest rounded-xl transition-all ${type === 'income' ? 'bg-gray-700 text-emerald-400 shadow-lg shadow-black/20 ring-1 ring-white/10' : 'text-gray-500 hover:text-gray-300'}`}>Income</button>
                    <button type="button" onClick={() => { setType('transfer'); setPartyId(''); }} className={`py-3 text-xs font-bold uppercase tracking-widest rounded-xl transition-all ${type === 'transfer' ? 'bg-gray-700 text-blue-400 shadow-lg shadow-black/20 ring-1 ring-white/10' : 'text-gray-500 hover:text-gray-300'}`}>Transfer</button>
                </div>

                <div>
                    <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Amount {mode === 'template' && '(Optional)'}</label>
                    <div className="flex gap-2">
                        <div className="relative flex-1">
                        <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gold-500 text-xl font-bold">{selectedCurrencySymbol}</span>
                        <input 
                            type="text" 
                            inputMode="decimal"
                            value={amount} 
                            onChange={(e) => setAmount(e.target.value)} 
                            onBlur={handleAmountBlur}
                            className="w-full pl-12 pr-4 py-4 text-3xl font-bold text-white bg-gray-950 border border-gray-700 rounded-2xl focus:ring-2 focus:ring-primary focus:border-transparent outline-none placeholder-gray-800" 
                            placeholder={mode === 'template' ? "0.00 (Optional)" : "0.00"}
                            required={mode === 'transaction'}
                        />
                        </div>
                        <div className="w-24">
                            <select 
                                value={currency} 
                                onChange={(e) => setCurrency(e.target.value as CurrencyCode)} 
                                className="w-full h-full px-2 bg-gray-950 text-white border border-gray-700 rounded-2xl focus:ring-2 focus:ring-primary outline-none font-bold text-center appearance-none"
                            >
                                {sortedCurrencies.map(c => (
                                    <option key={c.code} value={c.code}>{c.code}</option>
                                ))}
                            </select>
                        </div>
                    </div>
                    {/* Math Toolbar */}
                    <div className="flex gap-2 mt-2 overflow-x-auto no-scrollbar pb-1">
                        {['+', '-', '*', '/', '(', ')'].map(op => (
                            <button
                                key={op}
                                type="button"
                                tabIndex={-1}
                                onMouseDown={(e) => e.preventDefault()}
                                onClick={() => setAmount(prev => prev + op)}
                                className="flex-1 min-w-[40px] h-10 bg-gray-800 hover:bg-gray-700 text-gold-400 font-bold rounded-lg border border-gray-700 flex items-center justify-center text-lg active:scale-95 transition-transform"
                            >
                                {op === '*' ? '×' : op === '/' ? '÷' : op}
                            </button>
                        ))}
                    </div>
                </div>

                {type === 'transfer' ? (
                     <div className="grid grid-cols-1 gap-5 p-5 bg-blue-900/10 border border-blue-500/20 rounded-2xl relative overflow-hidden">
                        <div className="absolute top-0 right-0 p-3 opacity-5">
                          <ArrowRightLeft size={64} className="text-blue-500" />
                        </div>
                        <div>
                            <label className="block text-[10px] font-bold text-blue-400 uppercase tracking-widest mb-1.5">From Account (Credit)</label>
                            <SearchableSelect
                                options={transferSourceAccounts}
                                value={paymentAccountId}
                                onChange={setPaymentAccountId}
                                placeholder="Select Source..."
                                required
                            />
                        </div>
                        <div className="flex justify-center -my-3 relative z-10">
                            <div className="bg-gray-900 border border-blue-500/30 p-2 rounded-full shadow-lg">
                              <ArrowRight className="text-blue-500 rotate-90" size={16} />
                            </div>
                        </div>
                        <div>
                            <label className="block text-[10px] font-bold text-blue-400 uppercase tracking-widest mb-1.5">To Account (Debit)</label>
                            <SearchableSelect
                                options={availableAccounts}
                                value={accountId}
                                onChange={handleAccountChange}
                                placeholder="Select Destination..."
                                required
                            />
                        </div>
                     </div>
                ) : (
                    <div className="space-y-4">
                        <div>
                            <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Classification ({type === 'income' ? 'Revenue' : 'Expense'})</label>
                            <SearchableSelect
                                options={availableAccounts}
                                value={accountId}
                                onChange={handleAccountChange}
                                placeholder="Select Account..."
                                required
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Payment via</label>
                                <SearchableSelect
                                    options={[{id: '', label: 'None'}, ...transferSourceAccounts]}
                                    value={paymentAccountId}
                                    onChange={setPaymentAccountId}
                                    placeholder="Source..."
                                />
                            </div>
                            <div>
                                <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1 truncate">{type === 'income' ? 'Payer' : 'Merchant'}</label>
                                <SearchableSelect
                                    options={[{id: '', label: 'Opt...'}, ...availableParties]}
                                    value={partyId}
                                    onChange={setPartyId}
                                    placeholder="Party..."
                                />
                            </div>
                        </div>
                    </div>
                )}

                {mode === 'transaction' && (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Effective Date</label>
                            <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="w-full px-4 py-3.5 bg-gray-950 text-white border border-gray-700 rounded-2xl text-sm focus:ring-2 focus:ring-primary outline-none" />
                        </div>
                    </div>
                )}

                {!initialData && mode === 'transaction' && (
                    <div className="p-4 bg-gray-950/50 rounded-2xl border border-gray-800">
                        <div className="flex items-center gap-3 mb-2">
                            <input 
                                type="checkbox" 
                                id="isRecurring"
                                checked={isRecurring} 
                                onChange={e => setIsRecurring(e.target.checked)} 
                                className="w-5 h-5 rounded-lg bg-gray-900 border-gray-700 focus:ring-primary text-primary" 
                            />
                            <label htmlFor="isRecurring" className="text-sm font-bold text-gray-300 flex items-center gap-2 cursor-pointer">
                                <Repeat size={14} className="text-gold-500" />
                                Automate Transaction?
                            </label>
                        </div>
                        {isRecurring && (
                            <div className="flex items-center gap-3 animate-fade-in pl-8 mt-2">
                                <span className="text-xs text-gray-500 font-bold uppercase tracking-wider">Interval:</span>
                                <select 
                                    className="px-4 py-2 bg-gray-900 border border-gray-700 rounded-xl text-white text-xs outline-none focus:border-gold-500 font-bold uppercase" 
                                    value={recurFreq} 
                                    onChange={e => setRecurFreq(e.target.value as RecurrenceFrequency)}
                                >
                                    <option value="daily">Daily</option>
                                    <option value="weekly">Weekly</option>
                                    <option value="monthly">Monthly</option>
                                    <option value="yearly">Yearly</option>
                                </select>
                            </div>
                        )}
                    </div>
                )}

                <div>
                    <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Memo / Reference</label>
                    <textarea value={note} onChange={(e) => setNote(e.target.value)} className="w-full px-4 py-3 bg-gray-950 text-white border border-gray-700 rounded-2xl text-sm focus:ring-2 focus:ring-primary outline-none resize-none h-24 placeholder-gray-900" placeholder="Type notes here..." />
                </div>

                <div className="pt-2">
                   <button 
                        ref={submitBtnRef}
                        type="submit" 
                        className="w-full flex items-center justify-center gap-3 py-4 bg-primary hover:bg-blue-600 text-white rounded-2xl font-bold transition-all shadow-xl shadow-blue-900/30 active:scale-[0.98] btn-float text-sm uppercase tracking-widest"
                   >
                      {mode === 'template' ? <Save size={20} /> : (initialData ? <Save size={20} /> : <Check size={20} />)}
                      {mode === 'template' ? 'Save Shortcut' : (initialData ? 'Commit Update' : 'Commit Entry')}
                  </button>
                </div>
            </form>
        )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { useFinance } from '../context/FinanceContext';
import { format, startOfMonth, endOfMonth, parseISO, isWithinInterval, startOfYear, endOfYear } from 'date-fns';
import { PieChart, Pie, Cell, ResponsiveContainer } from 'recharts';
import { ChevronLeft, ChevronRight, Settings, Target, CheckSquare, Square, Copy, Calendar, Lock } from 'lucide-react';
import { Modal } from '../components/ui/Modal';
import { MonthlyBudget } from '../types';

export const Budget: React.FC = () => {
  const { state, dispatch } = useFinance();
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [viewMode, setViewMode] = useState<'monthly' | 'yearly'>('monthly');
  const [isManageOpen, setIsManageOpen] = useState(false);

  // Copy Modal State
  const [isCopyModalOpen, setIsCopyModalOpen] = useState(false);
  const [copyTargetType, setCopyTargetType] = useState<'single' | 'year'>('single');
  const [copyTargetValue, setCopyTargetValue] = useState(''); // YYYY-MM for single, YYYY for year

  const currency = state.businessProfile.baseCurrency || 'QAR';

  const budgetKey = viewMode === 'monthly' ? format(selectedDate, 'yyyy-MM') : format(selectedDate, 'yyyy');
  const periodStart = viewMode === 'monthly' ? startOfMonth(selectedDate) : startOfYear(selectedDate);
  const periodEnd = viewMode === 'monthly' ? endOfMonth(selectedDate) : endOfYear(selectedDate);

  // --- YEARLY AGGREGATION LOGIC ---
  const calculatedYearlyBudget = useMemo(() => {
      if (viewMode !== 'yearly') return undefined;
      const year = format(selectedDate, 'yyyy');

      let totalLimit = 0;
      const aggregatedCategoryLimits: Record<string, number> = {};
      const allVisibleAccountIds = new Set<string>();

      // Iterate through all 12 months of the selected year
      for (let i = 1; i <= 12; i++) {
          const monthKey = `${year}-${String(i).padStart(2, '0')}`;
          const monthBudget = state.monthlyBudgets?.find(b => b.monthKey === monthKey);

          if (monthBudget) {
              totalLimit += monthBudget.limit;

              // Sum category limits
              if (monthBudget.categoryLimits) {
                  Object.entries(monthBudget.categoryLimits).forEach(([accId, limit]) => {
                      aggregatedCategoryLimits[accId] = (aggregatedCategoryLimits[accId] || 0) + (limit as number);
                  });
              }

              // Collect visible accounts (Union of all months)
              if (monthBudget.visibleAccountIds) {
                  monthBudget.visibleAccountIds.forEach(id => allVisibleAccountIds.add(id));
              }
          }
      }

      const derived: MonthlyBudget = {
          monthKey: year,
          limit: totalLimit,
          categoryLimits: aggregatedCategoryLimits,
          visibleAccountIds: Array.from(allVisibleAccountIds)
      };
      return derived;

  }, [viewMode, selectedDate, state.monthlyBudgets]);

  // Get existing budget for this period (or derived if yearly)
  const existingBudget = viewMode === 'yearly' 
      ? calculatedYearlyBudget 
      : state.monthlyBudgets?.find(b => b.monthKey === budgetKey);

  const categoryLimits: Record<string, number> = existingBudget?.categoryLimits || {};

  // Fallback to all Expense accounts if no budget exists/visibility defined
  const visibleAccountIds = existingBudget?.visibleAccountIds && existingBudget.visibleAccountIds.length > 0
      ? existingBudget.visibleAccountIds
      : state.accounts.filter(c => c.class === 'Expenses').map(c => c.id);

  // Calculate actual spending per account for this period
  const actualSpending = useMemo(() => {
    const spending: Record<string, number> = {};
    state.transactions.filter(t => {
      const d = parseISO(t.date);
      return isWithinInterval(d, { start: periodStart, end: periodEnd }) && t.type === 'expense';
    }).forEach(t => {
      spending[t.accountId] = (spending[t.accountId] || 0) + t.amount;
    });
    return spending;
  }, [state.transactions, periodStart, periodEnd]);

  // Expense Accounts
  const allExpenseAccounts = state.accounts.filter(c => c.class === 'Expenses');
  const activeAccounts = allExpenseAccounts.filter(c => visibleAccountIds.includes(c.id));

  // Handlers
  const handleLimitChange = (accId: string, val: string) => {
      if (viewMode === 'yearly') return; // Prevent editing in yearly mode

      const limit = parseFloat(val) || 0;
      const newLimits = { ...categoryLimits, [accId]: limit };

      // Calculate Total from visible
      const totalLimit = Object.entries(newLimits)
        .filter(([id]) => visibleAccountIds.includes(id))
        .reduce((sum, [_, amt]) => sum + (amt as number), 0);

      dispatch({
          type: 'SET_MONTHLY_BUDGET',
          payload: {
              monthKey: budgetKey,
              limit: totalLimit,
              categoryLimits: newLimits,
              visibleAccountIds
          }
      });
  };

  const handleVisibleToggle = (accId: string) => {
      if (viewMode === 'yearly') return; // Prevent editing visibility in yearly mode directly (though aggregation handles it)

      const newVisible = visibleAccountIds.includes(accId) 
        ? visibleAccountIds.filter(id => id !== accId)
        : [...visibleAccountIds, accId];

      const totalLimit = Object.entries(categoryLimits)
        .filter(([id]) => newVisible.includes(id))
        .reduce((sum, [_, amt]) => sum + (amt as number), 0);

      dispatch({
          type: 'SET_MONTHLY_BUDGET',
          payload: {
              monthKey: budgetKey,
              limit: totalLimit,
              categoryLimits,
              visibleAccountIds: newVisible
          }
      });
  };

  const changePeriod = (delta: number) => {
      const newDate = new Date(selectedDate);
      if (viewMode === 'monthly') newDate.setMonth(newDate.getMonth() + delta);
      else newDate.setFullYear(newDate.getFullYear() + delta);
      setSelectedDate(newDate);
  };

  const handleCopyBudget = (e: React.FormEvent) => {
      e.preventDefault();
      // Ensure we are copying from a concrete monthly record
      if (!existingBudget || viewMode === 'yearly') return;

      if (!copyTargetValue) {
          alert("Please select a target.");
          return;
      }

      const targets: string[] = [];

      if (copyTargetType === 'single') {
          // Input type="month" returns YYYY-MM
          targets.push(copyTargetValue);
      } else {
          // Input type="number" returns YYYY
          const year = parseInt(copyTargetValue);
          if (isNaN(year) || year < 2000 || year > 2100) {
              alert("Invalid year.");
              return;
          }
          for (let i = 1; i <= 12; i++) {
              const m = String(i).padStart(2, '0');
              targets.push(`${year}-${m}`);
          }
      }

      // Perform Copy
      targets.forEach(targetKey => {
          dispatch({
              type: 'SET_MONTHLY_BUDGET',
              payload: {
                  monthKey: targetKey,
                  limit: existingBudget.limit,
                  categoryLimits: { ...existingBudget.categoryLimits },
                  visibleAccountIds: [...existingBudget.visibleAccountIds]
              }
          });
      });

      alert(`Budget copied to ${targets.length} month(s).`);
      setIsCopyModalOpen(false);
      setCopyTargetValue('');
  };

  // Stats
  const totalBudget = existingBudget?.limit || 0;
  const totalActual = activeAccounts.reduce((sum, cat) => sum + (actualSpending[cat.id] || 0), 0);
  const remaining = totalBudget - totalActual;
  const percentage = totalBudget > 0 ? (totalActual / totalBudget) * 100 : 0;

  const chartData = [
      { name: 'Used', value: totalActual, color: percentage > 100 ? '#ef4444' : '#3b82f6' },
      { name: 'Remaining', value: Math.max(0, remaining), color: '#1f2937' }
  ];

  return (
    <div className="space-y-6 pb-20 md:pb-0 animate-slide-up">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
            <h1 className="text-3xl font-bold text-white tracking-tight">Budget Planner</h1>
            <p className="text-gray-400 text-sm">
                {viewMode === 'monthly' 
                    ? `Allocate funds for ${format(selectedDate, 'MMMM yyyy')}` 
                    : `Yearly Aggregation for ${format(selectedDate, 'yyyy')}`
                }
            </p>
        </div>
        <div className="flex items-center gap-4">
            <div className="bg-gray-900 rounded-lg p-1 border border-gray-700 flex">
                <button onClick={() => setViewMode('monthly')} className={`px-3 py-1.5 rounded-md text-xs font-bold transition-all ${viewMode === 'monthly' ? 'bg-primary text-white' : 'text-gray-400 hover:text-white'}`}>Monthly</button>
                <button onClick={() => setViewMode('yearly')} className={`px-3 py-1.5 rounded-md text-xs font-bold transition-all ${viewMode === 'yearly' ? 'bg-primary text-white' : 'text-gray-400 hover:text-white'}`}>Yearly</button>
            </div>
            <div className="flex items-center gap-2 bg-gray-900 rounded-lg p-1 border border-gray-700">
                <button onClick={() => changePeriod(-1)} className="p-2 hover:bg-gray-800 rounded-lg text-gray-400"><ChevronLeft size={20}/></button>
                <span className="font-mono text-sm font-bold w-32 text-center text-white">{viewMode === 'monthly' ? format(selectedDate, 'MMM yyyy') : format(selectedDate, 'yyyy')}</span>
                <button onClick={() => changePeriod(1)} className="p-2 hover:bg-gray-800 rounded-lg text-gray-400"><ChevronRight size={20}/></button>
            </div>
            {viewMode === 'monthly' && (
                <button 
                    onClick={() => setIsCopyModalOpen(true)} 
                    disabled={!existingBudget}
                    className="p-2.5 bg-gray-800 hover:bg-gray-700 text-white rounded-lg border border-gray-700 transition-colors disabled:opacity-30 disabled:cursor-not-allowed"
                    title="Copy Budget to other months"
                >
                    <Copy size={18} />
                </button>
            )}
            <button 
                onClick={() => setIsManageOpen(true)} 
                className="p-2.5 bg-gray-800 hover:bg-gray-700 text-white rounded-lg border border-gray-700 transition-colors disabled:opacity-30 disabled:cursor-not-allowed"
                disabled={viewMode === 'yearly'}
                title={viewMode === 'yearly' ? "Switch to Monthly to manage categories" : "Manage Categories"}
            >
                <Settings size={18} />
            </button>
        </div>
      </div>

      {viewMode === 'yearly' && (
          <div className="bg-blue-900/20 border border-blue-500/30 p-3 rounded-xl flex items-center gap-3 text-sm text-blue-300">
              <Lock size={16} />
              <span>Yearly view is read-only. It represents the sum of all monthly budgets. Edit specific months to adjust the yearly plan.</span>
          </div>
      )}

      {/* Overview Card */}
      <div className="glass-card p-6 rounded-2xl flex flex-col md:flex-row items-center gap-8 border border-white/5 bg-gray-900/50">
           <div className="relative w-32 h-32 flex-shrink-0">
               <ResponsiveContainer width="100%" height="100%">
                   <PieChart>
                       <Pie data={chartData} innerRadius={35} outerRadius={50} dataKey="value" stroke="none">
                            {chartData.map((entry, index) => <Cell key={index} fill={entry.color} />)}
                       </Pie>
                   </PieChart>
               </ResponsiveContainer>
               <div className="absolute inset-0 flex items-center justify-center flex-col">
                   <span className="text-xs text-gray-500">Spent</span>
                   <span className={`font-bold ${percentage > 100 ? 'text-red-500' : 'text-blue-500'}`}>{percentage.toFixed(0)}%</span>
               </div>
           </div>

           <div className="flex-1 grid grid-cols-2 md:grid-cols-3 gap-6 text-center md:text-left">
               <div>
                   <p className="text-xs uppercase text-gray-500 font-bold">Total Budget</p>
                   <p className="text-2xl font-bold text-white mt-1">{currency} {totalBudget.toLocaleString()}</p>
               </div>
               <div>
                   <p className="text-xs uppercase text-gray-500 font-bold">Actual Spent</p>
                   <p className={`text-2xl font-bold mt-1 ${totalActual > totalBudget ? 'text-red-400' : 'text-white'}`}>{currency} {totalActual.toLocaleString()}</p>
               </div>
               <div>
                   <p className="text-xs uppercase text-gray-500 font-bold">Remaining</p>
                   <p className={`text-2xl font-bold mt-1 ${remaining < 0 ? 'text-red-500' : 'text-emerald-400'}`}>{currency} {remaining.toLocaleString()}</p>
               </div>
           </div>
      </div>

      {/* Category List */}
      <div className="space-y-4">
          <div className="flex justify-between items-end border-b border-gray-800 pb-2">
            <h3 className="text-lg font-bold text-white">Category Allocations</h3>
            {viewMode === 'yearly' && <span className="text-xs text-gray-500 italic"><Lock size={12} className="inline mr-1"/> Aggregated Values</span>}
          </div>
          <div className="grid gap-3 md:grid-cols-2 lg:grid-cols-3">
              {activeAccounts.map(cat => {
                  const limit = categoryLimits[cat.id] || 0;
                  const spent = actualSpending[cat.id] || 0;
                  const catRemaining = limit - spent;
                  const catPercent = limit > 0 ? (spent / limit) * 100 : 0;

                  return (
                      <div key={cat.id} className={`bg-gray-950/50 border ${viewMode === 'yearly' ? 'border-gray-800/50' : 'border-gray-800'} p-4 rounded-xl flex flex-col gap-3 group hover:border-gray-700 transition-colors`}>
                          <div className="flex justify-between items-start">
                              <div className="flex items-center gap-2">
                                  {/* No color in new Account, use generic dot */}
                                  <div className="w-2 h-2 rounded-full bg-blue-500"/>
                                  <span className="font-medium text-gray-300">{cat.name}</span>
                              </div>
                              <div className={`flex items-center gap-1 bg-gray-900 rounded-lg border border-gray-800 px-2 py-1 transition-all ${viewMode === 'monthly' ? 'focus-within:border-blue-500 focus-within:ring-1 focus-within:ring-blue-500' : 'opacity-70 cursor-not-allowed'}`}>
                                  {viewMode === 'yearly' && <Lock size={10} className="text-gray-600" />}
                                  <span className="text-xs text-gray-500">{currency}</span>
                                  <input 
                                    type="number" 
                                    className={`w-20 bg-transparent text-right text-sm font-bold text-white outline-none ${viewMode === 'yearly' ? 'cursor-not-allowed text-gray-400' : ''}`}
                                    placeholder="0"
                                    value={limit || ''}
                                    onChange={e => handleLimitChange(cat.id, e.target.value)}
                                    disabled={viewMode === 'yearly'}
                                  />
                              </div>
                          </div>

                          <div className="space-y-1">
                              <div className="flex justify-between text-xs text-gray-500">
                                  <span>Spent: {spent.toLocaleString()}</span>
                                  <span className={catRemaining < 0 ? 'text-red-400' : 'text-emerald-400'}>
                                      {catRemaining >= 0 ? 'Left: ' : 'Over: '} {Math.abs(catRemaining).toLocaleString()}
                                  </span>
                              </div>
                              <div className="h-1.5 bg-gray-800 rounded-full overflow-hidden">
                                  <div 
                                    className={`h-full rounded-full transition-all duration-500 ${catPercent > 100 ? 'bg-red-500' : 'bg-blue-500'}`} 
                                    style={{ width: `${Math.min(catPercent, 100)}%` }}
                                  />
                              </div>
                          </div>
                      </div>
                  );
              })}
              {activeAccounts.length === 0 && <div className="text-gray-500 text-sm col-span-full text-center py-10">No categories selected. Click settings to add some.</div>}
          </div>
      </div>

      <Modal isOpen={isManageOpen} onClose={() => setIsManageOpen(false)} title="Manage Budget Categories">
          <div className="space-y-2 max-h-[60vh] overflow-y-auto pr-2">
              {allExpenseAccounts.map(cat => (
                  <div key={cat.id} className="flex items-center justify-between p-3 bg-gray-900 rounded-xl border border-gray-800 hover:bg-gray-800 cursor-pointer" onClick={() => handleVisibleToggle(cat.id)}>
                      <div className="flex items-center gap-3">
                          <span className="text-sm font-medium text-gray-200">{cat.name}</span>
                      </div>
                      {visibleAccountIds.includes(cat.id) 
                        ? <CheckSquare size={20} className="text-primary" /> 
                        : <Square size={20} className="text-gray-600" />
                      }
                  </div>
              ))}
          </div>
      </Modal>

      {/* Copy Budget Modal */}
      <Modal isOpen={isCopyModalOpen} onClose={() => setIsCopyModalOpen(false)} title="Copy Budget">
          <form onSubmit={handleCopyBudget} className="space-y-6">
              <div className="p-4 bg-blue-900/10 border border-blue-500/20 rounded-xl">
                  <p className="text-xs text-blue-300 font-bold uppercase tracking-wider mb-1">Source</p>
                  <p className="text-white font-medium flex items-center gap-2">
                      <Calendar size={16} />
                      {format(selectedDate, 'MMMM yyyy')}
                  </p>
                  <p className="text-xs text-gray-400 mt-2">
                      This will overwrite the budget for the target selected below.
                  </p>
              </div>

              <div>
                  <label className="text-xs text-gray-500 font-bold uppercase tracking-wider mb-2 block">Target Type</label>
                  <div className="grid grid-cols-2 gap-3">
                      <button 
                          type="button"
                          onClick={() => { setCopyTargetType('single'); setCopyTargetValue(''); }}
                          className={`py-3 px-4 rounded-xl border text-sm font-bold transition-all ${copyTargetType === 'single' ? 'bg-primary border-primary text-white' : 'bg-gray-900 border-gray-700 text-gray-400 hover:bg-gray-800'}`}
                      >
                          Single Month
                      </button>
                      <button 
                          type="button"
                          onClick={() => { setCopyTargetType('year'); setCopyTargetValue(''); }}
                          className={`py-3 px-4 rounded-xl border text-sm font-bold transition-all ${copyTargetType === 'year' ? 'bg-primary border-primary text-white' : 'bg-gray-900 border-gray-700 text-gray-400 hover:bg-gray-800'}`}
                      >
                          Full Year
                      </button>
                  </div>
              </div>

              <div>
                  <label className="text-xs text-gray-500 font-bold uppercase tracking-wider mb-2 block">
                      {copyTargetType === 'single' ? 'Select Target Month' : 'Select Target Year'}
                  </label>
                  {copyTargetType === 'single' ? (
                      <input 
                          type="month" 
                          className="w-full px-4 py-3 bg-gray-900 border border-gray-700 rounded-xl text-white outline-none focus:border-primary"
                          value={copyTargetValue}
                          onChange={e => setCopyTargetValue(e.target.value)}
                          required
                      />
                  ) : (
                      <input 
                          type="number" 
                          min="2020" max="2100"
                          placeholder="YYYY"
                          className="w-full px-4 py-3 bg-gray-900 border border-gray-700 rounded-xl text-white outline-none focus:border-primary"
                          value={copyTargetValue}
                          onChange={e => setCopyTargetValue(e.target.value)}
                          required
                      />
                  )}
              </div>

              <button 
                  type="submit"
                  className="w-full py-3 bg-gradient-to-r from-primary to-blue-600 hover:from-blue-600 hover:to-primary text-white font-bold rounded-xl shadow-lg transition-all active:scale-95"
              >
                  Copy Budget
              </button>
          </form>
      </Modal>
    </div>
  );
};

import React, { useMemo, useState, useEffect } from 'react';
import { useFinance } from '../context/FinanceContext';
import { format, startOfMonth, endOfMonth, parseISO, isWithinInterval, isPast } from 'date-fns';
import { Calendar, FileText, Scale, Users, Download, Activity, Table, ScrollText, ArrowRightLeft, FileSpreadsheet, Camera, Printer, ChevronDown, ChevronRight } from 'lucide-react';
import { StatementOfAccount } from '../components/StatementOfAccount';
import { buildAccountTree, AccountNode } from '../utils/accountHierarchy';
import { Transaction, AccountClass } from '../types';
import { useLocation } from 'react-router-dom';
import html2canvas from 'html2canvas';
import * as XLSX from 'xlsx';

type ReportTab = 'income_statement' | 'balance_sheet' | 'cash_flow' | 'trial_balance' | 'soa';

const formatCurrency = (amount: number) => {
  return amount.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2});
};

interface ReportSectionProps {
  title: string;
  total: number;
  children: React.ReactNode;
  variant?: 'emerald' | 'orange' | 'red' | 'blue' | 'gray';
}

const ReportSection: React.FC<ReportSectionProps> = ({ title, total, children, variant = 'gray' }) => {
  const [isOpen, setIsOpen] = useState(true);

  const styles = {
      emerald: { text: 'text-emerald-700', border: 'border-emerald-700', bg: 'hover:bg-emerald-50' },
      orange: { text: 'text-orange-700', border: 'border-orange-700', bg: 'hover:bg-orange-50' },
      red: { text: 'text-red-700', border: 'border-red-700', bg: 'hover:bg-red-50' },
      blue: { text: 'text-blue-700', border: 'border-blue-700', bg: 'hover:bg-blue-50' },
      gray: { text: 'text-gray-800', border: 'border-gray-800', bg: 'hover:bg-gray-50' },
  }[variant];

  return (
    <div className="mb-6">
        <button 
            onClick={() => setIsOpen(!isOpen)}
            className={`w-full flex justify-between items-center py-2 border-b-2 ${styles.border} ${styles.bg} transition-colors group select-none`}
        >
            <div className={`flex items-center gap-2 ${styles.text}`}>
                {isOpen ? <ChevronDown size={18} /> : <ChevronRight size={18} />}
                <h4 className="font-bold uppercase text-sm">{title}</h4>
            </div>
            <span className={`font-bold ${styles.text}`}>
                {formatCurrency(total)}
            </span>
        </button>
        <div className={`overflow-hidden transition-all duration-500 ease-in-out ${isOpen ? 'max-h-[2000px] opacity-100' : 'max-h-0 opacity-0'}`}>
            <div className="pt-2 pl-6 space-y-1">
                {children}
            </div>
        </div>
    </div>
  );
};

export const Reports: React.FC = () => {
  const { state } = useFinance();
  const location = useLocation();
  const [activeTab, setActiveTab] = useState<ReportTab>('income_statement');
  const [initialSoaAccount, setInitialSoaAccount] = useState<string>('');

  const [dateRange, setDateRange] = useState({
    start: format(startOfMonth(new Date()), 'yyyy-MM-dd'),
    end: format(endOfMonth(new Date()), 'yyyy-MM-dd')
  });

  // Handle incoming shortcuts from other pages
  useEffect(() => {
      if (location.state && location.state.tab === 'soa') {
          setActiveTab('soa');
          if (location.state.accountId) {
              setInitialSoaAccount(location.state.accountId);
          }
      }
  }, [location]);

  // --- DATA CALCULATIONS ---

  const transactionsInPeriod = useMemo(() => {
    return state.transactions.filter(t => {
      const d = parseISO(t.date);
      const start = parseISO(dateRange.start);
      const end = parseISO(dateRange.end);
      end.setHours(23, 59, 59, 999);
      return isWithinInterval(d, { start, end });
    });
  }, [state.transactions, dateRange]);

  // 1. Balance Sheet Tree (Cumulative up to End Date)
  const balanceSheetTree = useMemo(() => {
      const endDate = parseISO(dateRange.end);
      endDate.setHours(23, 59, 59, 999);

      const bsTransactions = state.transactions.filter(t => parseISO(t.date) <= endDate);

      // Calculate Net Income for Retained Earnings Injection
      let totalRevenue = 0;
      let totalExpenses = 0;

      state.accounts.forEach(acc => {
          if (!acc.isPosting) return;
          if (acc.class !== 'Revenue' && acc.class !== 'Expenses') return;

          let dr = 0; 
          let cr = 0;
          bsTransactions.forEach(t => {
             if (t.accountId === acc.id) dr += t.amount;
             if (t.paymentAccountId === acc.id) cr += t.amount;
          });

          if (acc.class === 'Revenue') {
              totalRevenue += (cr - dr); 
          } else {
              totalExpenses += (dr - cr); 
          }
      });

      const netIncome = totalRevenue - totalExpenses;
      const retainedEarningsAcc = state.accounts.find(a => a.code === '32000' || a.name === 'Retained Earnings');
      let modifiedTransactions = [...bsTransactions];

      if (retainedEarningsAcc && Math.abs(netIncome) > 0.001) {
          const isProfit = netIncome > 0;
          const virtualTx: Transaction = {
              id: 'virtual_ni_adjustment',
              date: endDate.toISOString(),
              type: 'income',
              amount: Math.abs(netIncome),
              currency: 'QAR',
              source: 'personal',
              accountId: isProfit ? 'virtual_contra' : retainedEarningsAcc.id,
              paymentAccountId: isProfit ? retainedEarningsAcc.id : 'virtual_contra'
          };
          modifiedTransactions.push(virtualTx);
      }

      return buildAccountTree(state.accounts, modifiedTransactions);
  }, [state.accounts, state.transactions, dateRange.end]);

  // 2. Income Statement (Period Only)
  const incomeStatement = useMemo(() => {
      const getPeriodBalance = (accountId: string, type: 'revenue' | 'expense') => {
          let bal = 0;
          transactionsInPeriod.forEach(t => {
              if (t.accountId === accountId) bal += t.amount; 
              if (t.paymentAccountId === accountId) bal -= t.amount; 
          });
          // Revenue is Credit normal (negative balance), convert to positive for display
          if (type === 'revenue') return -(bal);
          // Expense is Debit normal (positive balance), keep positive
          return bal;
      };

      const revenueAccs = state.accounts.filter(c => c.class === 'Revenue' && c.isPosting);
      const allExpenseAccs = state.accounts.filter(c => c.class === 'Expenses' && c.isPosting);

      const revenueBreakdown = revenueAccs.map(a => ({ name: a.name, amount: getPeriodBalance(a.id, 'revenue') })).filter(i => Math.abs(i.amount) > 0.01);

      // Separate Direct Costs (Code starts with 5) from Operating Expenses (others)
      const directCostBreakdown = allExpenseAccs
          .filter(a => a.code.startsWith('5')) 
          .map(a => ({ name: a.name, amount: getPeriodBalance(a.id, 'expense') }))
          .filter(i => Math.abs(i.amount) > 0.01);

      const operatingExpenseBreakdown = allExpenseAccs
          .filter(a => !a.code.startsWith('5'))
          .map(a => ({ name: a.name, amount: getPeriodBalance(a.id, 'expense') }))
          .filter(i => Math.abs(i.amount) > 0.01);

      const totalRevenue = revenueBreakdown.reduce((s, i) => s + i.amount, 0);
      const totalDirectCosts = directCostBreakdown.reduce((s, i) => s + i.amount, 0);
      const grossProfit = totalRevenue - totalDirectCosts;
      const totalOperatingExpenses = operatingExpenseBreakdown.reduce((s, i) => s + i.amount, 0);
      const netIncome = grossProfit - totalOperatingExpenses;

      return { 
          revenueBreakdown, 
          totalRevenue, 
          directCostBreakdown, 
          totalDirectCosts, 
          grossProfit, 
          operatingExpenseBreakdown, 
          totalOperatingExpenses, 
          netIncome 
      };
  }, [transactionsInPeriod, state.accounts]);

  // 3. Cash Flow (Direct Method)
  const cashFlowStatement = useMemo(() => {
      const cashGroup = state.accounts.find(a => a.name.includes('Cash & Cash Equivalents') || a.code === '11100');
      const cashAccountIds = state.accounts
          .filter(a => a.parentId === cashGroup?.id || a.code.startsWith('111'))
          .map(a => a.id);

      const report = { operating: { in: 0, out: 0 }, investing: { in: 0, out: 0 }, financing: { in: 0, out: 0 }, startCash: 0, endCash: 0 };
      const startDate = parseISO(dateRange.start);

      state.transactions.filter(t => parseISO(t.date) < startDate).forEach(t => {
          if (cashAccountIds.includes(t.accountId)) report.startCash += t.amount; 
          if (cashAccountIds.includes(t.paymentAccountId || '')) report.startCash -= t.amount; 
      });

      transactionsInPeriod.forEach(t => {
          const isCashDr = cashAccountIds.includes(t.accountId);
          const isCashCr = cashAccountIds.includes(t.paymentAccountId || '');
          if (isCashDr && isCashCr) return;

          if (isCashDr) {
              const contraAcc = state.accounts.find(a => a.id === t.paymentAccountId);
              if (contraAcc) {
                  const cat = contraAcc.class;
                  if (cat === 'Revenue' || cat === 'Expenses') report.operating.in += t.amount;
                  else if (cat === 'Assets') {
                      if (contraAcc.code.startsWith('12')) report.investing.in += t.amount;
                      else report.operating.in += t.amount;
                  } else report.financing.in += t.amount;
              } else report.financing.in += t.amount;
          } else if (isCashCr) {
              const contraAcc = state.accounts.find(a => a.id === t.accountId);
              if (contraAcc) {
                  const cat = contraAcc.class;
                  if (cat === 'Expenses' || cat === 'Revenue') report.operating.out += t.amount;
                  else if (cat === 'Assets') {
                      if (contraAcc.code.startsWith('12')) report.investing.out += t.amount;
                      else report.operating.out += t.amount;
                  } else if (cat === 'Liabilities') report.financing.out += t.amount;
                  else report.financing.out += t.amount;
              }
          }
      });

      const netOperating = report.operating.in - report.operating.out;
      const netInvesting = report.investing.in - report.investing.out;
      const netFinancing = report.financing.in - report.financing.out;
      const netChange = netOperating + netInvesting + netFinancing;

      return { ...report, netOperating, netInvesting, netFinancing, netChange, endCash: report.startCash + netChange };
  }, [state.transactions, state.accounts, transactionsInPeriod, dateRange]);

  // 4. Trial Balance (Cumulative up to End Date)
  const trialBalanceData = useMemo(() => {
      const endDate = parseISO(dateRange.end);
      endDate.setHours(23, 59, 59, 999);

      const relevantTxs = state.transactions.filter(t => parseISO(t.date) <= endDate);
      const balances: Record<string, number> = {};

      relevantTxs.forEach(t => {
          balances[t.accountId] = (balances[t.accountId] || 0) + t.amount; // Dr +
          if (t.paymentAccountId) {
              balances[t.paymentAccountId] = (balances[t.paymentAccountId] || 0) - t.amount; // Cr -
          }
      });

      const rows = state.accounts
          .filter(a => a.isPosting)
          .map(acc => {
              const bal = balances[acc.id] || 0;
              // Map to Debit/Credit columns based on sign
              // Positive = Debit Side, Negative = Credit Side (show as positive number)
              return {
                  ...acc,
                  balance: bal,
                  debit: bal > 0 ? bal : 0,
                  credit: bal < 0 ? Math.abs(bal) : 0
              };
          })
          .filter(r => Math.abs(r.balance) > 0.001);

      const groups: Record<AccountClass, typeof rows> = { 'Assets': [], 'Liabilities': [], 'Equity': [], 'Revenue': [], 'Expenses': [] };
      rows.forEach(r => { if (groups[r.class]) groups[r.class].push(r); });
      Object.keys(groups).forEach(k => groups[k as AccountClass].sort((a,b) => a.code.localeCompare(b.code)));

      const totalDebit = rows.reduce((sum, r) => sum + r.debit, 0);
      const totalCredit = rows.reduce((sum, r) => sum + r.credit, 0);

      return { groups, totalDebit, totalCredit };
  }, [state.accounts, state.transactions, dateRange.end]);

  // --- UTILS & HANDLERS ---

  const renderReportNode = (nodes: AccountNode[], indent = 0, multiplier = 1) => {
      return nodes.map(node => {
          const displayVal = node.totalBalance * multiplier;
          return (
            <React.Fragment key={node.id}>
                {Math.abs(node.totalBalance) > 0.01 && (
                    <div className="flex justify-between py-1 border-b border-gray-100 last:border-0 hover:bg-gray-50/50">
                        <span className={`pl-${indent * 4} ${node.level === 'group' || node.level === 'class' ? 'font-bold text-gray-800' : 'text-gray-600'} text-sm`}>
                            {node.name}
                        </span>
                        <span className={`text-sm font-mono ${node.level === 'group' ? 'font-bold' : ''}`}>
                            {formatCurrency(displayVal)}
                        </span>
                    </div>
                )}
                {node.children.length > 0 && renderReportNode(node.children, indent + 2, multiplier)}
            </React.Fragment>
          );
      });
  };

  const getNodeTotal = (nodes: AccountNode[]) => nodes.reduce((s, n) => s + n.totalBalance, 0);
  const totalAssets = getNodeTotal(balanceSheetTree['Assets']);
  const totalLiabilities = getNodeTotal(balanceSheetTree['Liabilities']);
  const totalEquity = getNodeTotal(balanceSheetTree['Equity']);

  const handleExcelExport = () => {
      const wb = XLSX.utils.book_new();
      let rows: any[] = [];
      let sheetName = "Report";
      let fileName = `Report_${dateRange.end}.xlsx`;

      if (activeTab === 'income_statement') {
          sheetName = "Income Statement";
          fileName = `IncomeStatement_${dateRange.start}_${dateRange.end}.xlsx`;
          rows = [
              { A: 'REVENUE' },
              ...incomeStatement.revenueBreakdown.map(r => ({ A: r.name, B: r.amount })),
              { A: 'TOTAL REVENUE', B: incomeStatement.totalRevenue },
              { A: '' },
              { A: 'DIRECT COSTS' },
              ...incomeStatement.directCostBreakdown.map(r => ({ A: r.name, B: r.amount })),
              { A: 'TOTAL DIRECT COSTS', B: incomeStatement.totalDirectCosts },
              { A: '' },
              { A: 'GROSS PROFIT', B: incomeStatement.grossProfit },
              { A: '' },
              { A: 'OPERATING EXPENSES' },
              ...incomeStatement.operatingExpenseBreakdown.map(r => ({ A: r.name, B: r.amount })),
              { A: 'TOTAL OPERATING EXPENSES', B: incomeStatement.totalOperatingExpenses },
              { A: '' },
              { A: 'NET INCOME', B: incomeStatement.netIncome }
          ];
      } else if (activeTab === 'balance_sheet') {
          sheetName = "Balance Sheet";
          fileName = `BalanceSheet_${dateRange.end}.xlsx`;
          // Simple flat export for BS
          const processNodes = (nodes: AccountNode[], multiplier: number) => {
              let flat: any[] = [];
              nodes.forEach(n => {
                  if (Math.abs(n.totalBalance) > 0.01) flat.push({ A: n.name, B: n.totalBalance * multiplier });
                  if (n.children) flat = [...flat, ...processNodes(n.children, multiplier)];
              });
              return flat;
          };
          rows = [
              { A: 'ASSETS' },
              ...processNodes(balanceSheetTree['Assets'], 1),
              { A: 'TOTAL ASSETS', B: totalAssets },
              { A: '' },
              { A: 'LIABILITIES' },
              ...processNodes(balanceSheetTree['Liabilities'], -1),
              { A: 'TOTAL LIABILITIES', B: totalLiabilities * -1 },
              { A: '' },
              { A: 'EQUITY' },
              ...processNodes(balanceSheetTree['Equity'], -1),
              { A: 'TOTAL EQUITY', B: totalEquity * -1 },
              { A: '' },
              { A: 'TOTAL LIAB & EQUITY', B: (totalLiabilities + totalEquity) * -1 }
          ];
      } else if (activeTab === 'trial_balance') {
          sheetName = "Trial Balance";
          fileName = `TrialBalance_${dateRange.end}.xlsx`;
          rows.push({ A: 'Account Code', B: 'Account Name', C: 'Debit', D: 'Credit' });
          ['Assets', 'Liabilities', 'Equity', 'Revenue', 'Expenses'].forEach(cls => {
              rows.push({ A: cls.toUpperCase() });
              trialBalanceData.groups[cls as AccountClass].forEach(r => {
                  rows.push({ A: r.code, B: r.name, C: r.debit, D: r.credit });
              });
          });
          rows.push({ A: 'TOTAL', B: '', C: trialBalanceData.totalDebit, D: trialBalanceData.totalCredit });
      } else if (activeTab === 'cash_flow') {
          sheetName = "Cash Flow";
          fileName = `CashFlow_${dateRange.start}_${dateRange.end}.xlsx`;
          rows = [
              { A: 'OPERATING ACTIVITIES', B: '' },
              { A: 'Cash In', B: cashFlowStatement.operating.in },
              { A: 'Cash Out', B: cashFlowStatement.operating.out * -1 },
              { A: 'Net Operating', B: cashFlowStatement.netOperating },
              { A: '' },
              { A: 'INVESTING ACTIVITIES', B: '' },
              { A: 'Cash In', B: cashFlowStatement.investing.in },
              { A: 'Cash Out', B: cashFlowStatement.investing.out * -1 },
              { A: 'Net Investing', B: cashFlowStatement.netInvesting },
              { A: '' },
              { A: 'FINANCING ACTIVITIES', B: '' },
              { A: 'Cash In', B: cashFlowStatement.financing.in },
              { A: 'Cash Out', B: cashFlowStatement.financing.out * -1 },
              { A: 'Net Financing', B: cashFlowStatement.netFinancing },
              { A: '' },
              { A: 'Net Change in Cash', B: cashFlowStatement.netChange },
              { A: 'Beginning Cash', B: cashFlowStatement.startCash },
              { A: 'Ending Cash', B: cashFlowStatement.endCash }
          ];
      }

      const ws = XLSX.utils.json_to_sheet(rows, { skipHeader: true });
      XLSX.utils.book_append_sheet(wb, ws, sheetName);
      XLSX.writeFile(wb, fileName);
  };

  return (
    <div className="space-y-6 pb-20 md:pb-0 animate-fade-in">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4 no-print">
            <div><h1 className="text-3xl font-bold text-white tracking-tight">Financial Reports</h1></div>
            {activeTab !== 'soa' && (
                <div className="flex gap-2 bg-gray-900 p-1 rounded-xl border border-gray-700">
                    <input type="date" value={dateRange.start} onChange={e => setDateRange(prev => ({...prev, start: e.target.value}))} className="bg-transparent text-white text-sm px-2 outline-none" />
                    <span className="text-gray-500">to</span>
                    <input type="date" value={dateRange.end} onChange={e => setDateRange(prev => ({...prev, end: e.target.value}))} className="bg-transparent text-white text-sm px-2 outline-none" />
                </div>
            )}
        </div>

        <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar no-print">
            {['income_statement', 'balance_sheet', 'cash_flow', 'trial_balance', 'soa'].map(t => (
                <button 
                    key={t} 
                    onClick={() => setActiveTab(t as ReportTab)} 
                    className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium whitespace-nowrap ${activeTab === t ? 'bg-primary text-white' : 'bg-gray-800 text-gray-400'}`}
                >
                    {t === 'trial_balance' && <Table size={14}/>}
                    {t === 'soa' ? 'SOA' : t.replace('_', ' ').replace(/\b\w/g, l => l.toUpperCase())}
                </button>
            ))}
        </div>

        {/* --- GLOBAL EXPORT BUTTON (Only for non-SOA tabs, SOA has its own control) --- */}
        {activeTab !== 'soa' && (
            <div className="flex justify-end no-print">
                <button 
                    onClick={handleExcelExport}
                    className="flex items-center gap-2 px-4 py-2 bg-emerald-800 hover:bg-emerald-700 text-white rounded-lg font-bold text-sm transition-colors"
                >
                    <FileSpreadsheet size={16} /> Export to Excel
                </button>
            </div>
        )}

        {/* --- TABS --- */}

        {activeTab === 'trial_balance' && (
            <div className="glass-card bg-white text-black p-8 rounded-2xl min-h-[600px] shadow-xl">
                <div className="text-center mb-8 border-b border-gray-200 pb-6">
                    <h2 className="text-2xl font-bold text-gray-900 uppercase">{state.businessProfile.name}</h2>
                    <h3 className="text-xl font-medium text-gray-600 mt-2">TRIAL BALANCE</h3>
                    <p className="text-sm text-gray-500">As of {dateRange.end}</p>
                </div>
                <div className="max-w-4xl mx-auto">
                    <table className="w-full text-sm text-left border-collapse">
                        <thead>
                            <tr className="bg-slate-800 text-white uppercase text-xs">
                                <th className="py-3 px-4 border-r border-slate-600 w-24">Code</th>
                                <th className="py-3 px-4 border-r border-slate-600">Account</th>
